/* =========================================================================
   quiz-data-extra.js — English Literature Quiz Extra Data
   Expands existing topics toward 100 questions each.
   Format: window.QUIZ_DATA[key].push({ q, opts:[a,b,c,d], ans:0-3, expl })
   ========================================================================= */

(function () {
  if (typeof window === 'undefined') return;
  if (!window.QUIZ_DATA) window.QUIZ_DATA = {};

  /* ══ GEORGE ORWELL (+76) ══ */
  window.QUIZ_DATA.orwell.push(
    { q:"What is the significance of the chestnut tree café in 1984?", opts:["It is where Winston first meets Julia","It is where broken Party enemies sit, including Winston at the end","It is the Brotherhood's headquarters","It is the Ministry of Love's canteen"], ans:1, expl:"The chestnut tree café is where former dissidents, now broken by the Party, sit alone — Winston ends up there." },
    { q:"What does Winston buy from Mr Charrington's shop?", opts:["A telescreen","A diary and later a glass paperweight","A Newspeak dictionary","A Party uniform"], ans:1, expl:"Winston buys a blank diary to begin his secret writing, and later a beautiful glass paperweight symbolising a vanished past." },
    { q:"What is the 'Golden Country' in Winston's dreams?", opts:["A vision of Oceania's capital","A recurring idyllic rural landscape representing freedom and the past","The Ministry of Plenty's propaganda image","A fictional foreign country"], ans:1, expl:"The Golden Country is Winston's recurring dream of an unspoiled natural landscape — a symbol of lost freedom and authenticity." },
    { q:"Who betrays Winston and Julia to the Thought Police?", opts:["O'Brien","Mr Charrington","Both O'Brien and Mr Charrington, who are secret agents","Syme"], ans:2, expl:"Both O'Brien and the seemingly kindly shopkeeper Mr Charrington are revealed to be Thought Police agents." },
    { q:"What is the function of the Two Minutes Hate?", opts:["A daily exercise routine","A ritual of collective fury directed at Party enemies to release tension and reinforce loyalty","A government meeting","A form of entertainment for children"], ans:2, expl:"The Two Minutes Hate channels citizens' frustrations into hatred of external enemies, strengthening loyalty to the Party." },
    { q:"What does Syme's fate (he is vaporised) illustrate?", opts:["The danger of being too competent at one's job","Even loyal Party members devoted to Newspeak can be eliminated without warning","Syme was secretly a rebel","Syme chose to leave the Party"], ans:1, expl:"Syme, an enthusiastic Newspeak expert, simply disappears — showing that no one, however loyal, is safe." },
    { q:"What is the 'memory hole'?", opts:["A storage room for old documents","A chute where incriminating documents are sent to be destroyed, erasing inconvenient facts","A hole in Winston's apartment wall","A secret meeting place"], ans:1, expl:"Documents that contradict the Party's current version of truth are dropped into memory holes and incinerated." },
    { q:"How does Winston's job relate to the theme of historical truth?", opts:["He preserves historical accuracy","He demonstrates how totalitarian regimes can rewrite the past to control the present and future","He writes fiction unrelated to history","He translates foreign news"], ans:1, expl:"By constantly rewriting records, the Party shows that 'who controls the past controls the future; who controls the present controls the past'." },
    { q:"What is Airstrip One?", opts:["A military base in Eurasia","The Oceanic province that was formerly known as Britain","A type of telescreen","The Ministry of Truth's airport"], ans:1, expl:"Airstrip One is the renamed Britain, now a province of the superstate Oceania." },
    { q:"What are the three superstates in 1984?", opts:["Oceania, Eurasia, Eastasia","America, Russia, China","Britain, Germany, Japan","Oceania, Atlantis, Eurasia"], ans:0, expl:"The world is divided into three perpetually warring superstates: Oceania, Eurasia and Eastasia." },
    { q:"What is the social hierarchy of the Party in 1984?", opts:["King, nobles, peasants","Inner Party, Outer Party, Proles","President, Senate, citizens","Leaders, soldiers, workers"], ans:2, expl:"The Inner Party (the elite, around 2%), the Outer Party (Winston's class, administrators) and the Proles (the masses)." },
    { q:"What does the Ministry of Love actually do?", opts:["Promotes marriage and family values","Is responsible for law, order and torture of dissidents","Distributes food rations","Manages international diplomacy"], ans:1, expl:"Despite its name, the Ministry of Love (Miniluv) houses the Thought Police and conducts interrogation and torture." },
    { q:"What is the irony in the names of Oceania's four ministries?", opts:["There is no irony — the names are accurate","Each ministry's name is the opposite of its true function (e.g. Ministry of Peace wages war)","The names are simply old-fashioned","The ministries have no real function"], ans:1, expl:"Ministry of Truth (lies), Peace (war), Love (torture), Plenty (scarcity) — Orwell's use of doublethink in naming." },
    { q:"What is the 'Brotherhood' in 1984?", opts:["A real and active resistance organisation","An alleged underground resistance movement that may be a Party invention to trap dissidents","A workers' union","A foreign intelligence agency"], ans:1, expl:"The Brotherhood may not exist at all — it could be a trap set by the Party (via O'Brien) to identify and capture thoughtcriminals." },
    { q:"What does Winston believe is humanity's only hope for revolution?", opts:["The Inner Party","The proles, due to their numbers and lack of indoctrination","Foreign invasion","The Outer Party"], ans:1, expl:"Winston believes that since the proles are the majority and largely free of Party conditioning, real change could only come from them — though he doubts it will happen." },
    { q:"What does Goldstein's book argue about the nature of war in Oceania?", opts:["War will eventually end in victory","Perpetual war is designed to consume surplus production and keep the population poor and obedient","War is fought to gain new territory","War has been abolished"], ans:1, expl:"The book explains that endless war prevents the population from becoming prosperous enough to think for themselves." },
    { q:"What is Winston's physical condition at the start of the novel?", opts:["He is strong and healthy","He is middle-aged, frail, with a varicose ulcer, reflecting the grim deprivation of Oceania","He is a young athlete","He is disabled from war injuries"], ans:1, expl:"Winston's poor health (varicose ulcer, bad teeth, thin body) reflects the material poverty of life under the Party." },
    { q:"What role does Victory Gin play in 1984?", opts:["It is a luxury reserved for the Inner Party","It is a cheap, harsh alcohol that numbs the population, symbolising the bleakness of daily life","It is used only in ceremonies","It is banned by the Party"], ans:1, expl:"Victory Gin is foul-tasting and widely consumed — a small comfort that also dulls critical thought." },
    { q:"Why does the Party discourage sexual pleasure in 1984?", opts:["For religious reasons","Because sexual energy redirected into Party loyalty (and frustration channelled into hatred) strengthens control","Because of overpopulation concerns","Because it is too expensive"], ans:1, expl:"The Party views sex purely as a duty for reproduction; pleasure is suppressed so that frustrated energy can be channelled into fervour for the Party." },
    { q:"What is the significance of the painting/picture hiding a telescreen in Winston's flat?", opts:["It shows Winston's artistic taste","It shows that surveillance can be hidden even in seemingly private spaces","It is a gift from Julia","It represents Winston's only possession"], ans:1, expl:"The telescreen behind the picture means even Winston's home is never truly private — total surveillance." },
    { q:"What does Animal Farm's ending (pigs walking on two legs) symbolise?", opts:["The animals have evolved naturally","The complete betrayal of the revolution — the pigs have become indistinguishable from the human oppressors they overthrew","A celebration of progress","The pigs have left the farm"], ans:1, expl:"The final image shows the pigs now resembling the humans, completing the cycle of oppression under a new name." },
    { q:"In Animal Farm, what does the character Boxer represent?", opts:["The intellectual elite","The hardworking, loyal but exploited working class","The secret police","The foreign powers"], ans:1, expl:"Boxer the horse works tirelessly for the farm's success but is betrayed and sent to slaughter when no longer useful — representing the exploited proletariat." },
    { q:"What does the character Squealer represent in Animal Farm?", opts:["The military","Propaganda and the manipulation of language to control public opinion","Foreign spies","The farm's original owner"], ans:1, expl:"Squealer is the pigs' spokesperson, twisting facts and language (early 'doublethink') to justify Napoleon's actions." },
    { q:"What happens to the windmill in Animal Farm and what does it represent?", opts:["It is built easily and brings prosperity to all","It is repeatedly destroyed and rebuilt, symbolising the endless toil demanded of the working animals for little benefit","It is sold to humans","It powers the farm perfectly from the start"], ans:1, expl:"The windmill's destruction (by storm, then by Snowball's alleged sabotage) and rebuilding represents wasted labour exploited by the ruling pigs." },
    { q:"What is the original name of the farm in Animal Farm, and what does its restoration at the end signify?", opts:["Sugarcandy Mountain — signifying paradise achieved","Manor Farm — its restoration signifies the return to the old order under new management","Animalia — signifying a new nation","Rebellion Farm — signifying ongoing revolution"], ans:1, expl:"Renaming the farm back to 'Manor Farm' at the end shows that the revolution has fully reverted to the original oppressive order." },
    { q:"What does the character Old Major represent in Animal Farm?", opts:["Joseph Stalin","Leon Trotsky","Karl Marx / Vladimir Lenin — the visionary whose ideas inspire the revolution but who dies before seeing it corrupted","Tsar Nicholas II"], ans:2, expl:"Old Major's speech inspires the rebellion (like Marxist theory inspiring the Russian Revolution), but he dies before the pigs corrupt his ideals." },
    { q:"What is the significance of the dogs in Animal Farm?", opts:["They represent loyal citizens","They represent Stalin's secret police (NKVD), used by Napoleon to intimidate and eliminate opposition","They represent foreign invaders","They represent the intellectual class"], ans:1, expl:"Napoleon raises the puppies to be his private army of enforcers, paralleling Stalin's use of the secret police to terrorise dissenters." },
    { q:"What does Mollie the horse represent in Animal Farm?", opts:["The revolutionary vanguard","Those who prefer comfort and vanity under the old regime to the hardships of revolution, and who abandon the cause","The intellectual elite","The working class"], ans:1, expl:"Mollie misses ribbons and sugar lumps from her old life and eventually leaves the farm — representing those uninterested in collective struggle." },
    { q:"How does Orwell's own experience in the Spanish Civil War influence his writing?", opts:["He never wrote about it","His experiences (described in Homage to Catalonia) deepened his hatred of totalitarianism, including from the political left","It made him a supporter of fascism","It had no influence on his later work"], ans:1, expl:"Orwell fought for a socialist militia in Spain and witnessed Stalinist suppression of other left-wing factions, shaping his anti-totalitarian views across the political spectrum." },
    { q:"What is the central message of Orwell's essay 'Politics and the English Language'?", opts:["English should be simplified into Newspeak","Vague, clichéd language corrupts thought, and clear writing is essential to honest political discourse","Politicians should avoid speaking in public","Language has no effect on politics"], ans:1, expl:"Orwell argues that political language is often designed to obscure truth, and that clear, precise language is a defence against propaganda." },
    { q:"What genre best describes 1984?", opts:["Romantic comedy","Dystopian science fiction / political satire","Historical fiction","Detective fiction"], ans:1, expl:"1984 combines dystopian science fiction with direct political satire of totalitarian regimes." },
    { q:"What does the term 'Orwellian' commonly refer to today?", opts:["A style of poetry","Situations involving propaganda, surveillance, misinformation and the manipulation of truth by authorities","A type of British humour","A literary award"], ans:1, expl:"'Orwellian' describes any practice associated with totalitarian control: surveillance, propaganda, doublethink and erasure of truth." },
    { q:"How does Winston initially feel about Big Brother at the very start of the novel, compared to the end?", opts:["He hates Big Brother throughout","He begins with private resentment and ends loving Big Brother after being broken","He loves Big Brother throughout","He is indifferent throughout"], ans:1, expl:"The novel traces Winston's journey from secret rebellion to complete psychological surrender — the tragedy of total control." },
    { q:"What is the function of the Appendix on Newspeak at the end of 1984?", opts:["It is a glossary for foreign readers only","It explains the principles of Newspeak in a detached, essay-like style, written as if from a future where the Party has fallen","It contains additional plot details","It is a list of Party slogans only"], ans:1, expl:"The Appendix is written in standard English in the past tense, suggesting Newspeak (and perhaps the Party) no longer exists — offering a sliver of hope." },
    { q:"What does the term 'prolefeed' refer to in 1984?", opts:["Food rations for the proles","Cheap entertainment and pornography produced by the Party to keep the proles distracted and docile","A type of propaganda poster","A Newspeak word for famine"], ans:1, expl:"Prolefeed is mass entertainment designed to pacify the proles, similar to Huxley's use of distraction in Brave New World." },
    { q:"How does the setting of Airstrip One (a decaying London) reflect post-WWII Britain?", opts:["It depicts a thriving, rebuilt city","It reflects the bomb damage, rationing and austerity of post-war Britain when Orwell was writing","It is set in a fantasy world unrelated to Britain","It depicts Britain before WWI"], ans:1, expl:"Orwell wrote 1984 in war-damaged, rationed post-war London, and the novel's grim, decaying setting reflects this reality." },
    { q:"What is the significance of Winston's age and physical decline?", opts:["It shows the Party rewards loyal members with good health","It represents the toll of life under constant surveillance, propaganda and material deprivation","It is irrelevant to the novel's themes","It shows Winston is actually very old"], ans:1, expl:"Winston's poor physical state at 39 reflects how the totalitarian system grinds down even those who serve it." },
    { q:"What does Julia's character primarily contrast with Winston's?", opts:["She is more politically committed than Winston","She is pragmatic and focused on personal survival and pleasure rather than ideological rebellion","She is older and more cynical","She works for the Thought Police"], ans:1, expl:"While Winston seeks meaning and truth, Julia simply wants to enjoy small personal freedoms — a different, more pragmatic form of resistance." },
    { q:"What happens to the rats in Room 101 and why are they significant?", opts:["They are Winston's pets","They represent Winston's deepest, most personal fear, which O'Brien exploits to break him completely","They are a Party experiment","They symbolise the proles"], ans:1, expl:"The Party's torture is tailored to each individual's worst fear — for Winston, rats — showing the totality of the Party's knowledge and control." },
    { q:"What is the effect of the novel's ending being deliberately bleak?", opts:["It shows the Party can always be defeated","It reinforces Orwell's warning that totalitarianism, once fully established, may be unbeatable — a call to vigilance before it is too late","It was an editorial requirement","It has a hidden happy ending"], ans:1, expl:"Orwell's bleak ending serves as a warning: resistance must come before total control is achieved, because afterwards it may be impossible." },
    { q:"What does the destruction of personal relationships (e.g. Winston's marriage to Katharine) reveal about the Party?", opts:["The Party encourages strong family bonds","The Party seeks to eliminate all loyalties except loyalty to itself, including love and family","The Party has no interest in private life","Marriage is banned entirely in Oceania"], ans:1, expl:"Katharine, like Winston, has been conditioned to see sex only as 'our duty to the Party' — intimacy and love are drained of meaning." },
    { q:"What is the importance of the children in 1984, such as the Parsons children?", opts:["They represent hope for the future outside the Party","They are shown as fervent, frightening informers, having been fully indoctrinated from birth — even reporting their own parents","They are largely absent from the novel","They are protected from Party ideology"], ans:1, expl:"The Parsons children embody the Party's success in creating a generation with no private loyalties beyond the Party — even denouncing their own father." },
    { q:"What is the relationship between language and thought as explored through Newspeak?", opts:["Language has no effect on thought","Language shapes and limits the capacity for thought — a form of linguistic determinism central to the novel's warning","Newspeak makes people more intelligent","Newspeak is simply a more efficient version of English"], ans:1, expl:"By eliminating words for dissenting concepts, the Party aims to make certain thoughts literally unthinkable — a chilling application of linguistic determinism." },
    { q:"How does Orwell use satire in Animal Farm to address universal political themes beyond just the USSR?", opts:["The satire applies only to Russia and nowhere else","The fable format allows the critique of how any revolution can be betrayed by its leaders, regardless of ideology","Animal Farm contains no satire","It is purely a children's story with no political meaning"], ans:1, expl:"While modelled on the Russian Revolution, the fable's structure makes it a universal warning about power corrupting revolutionary ideals in any context." },
    { q:"What is the function of the character Winston's neighbour Mr Parsons?", opts:["He is a secret rebel","He represents the ordinary, enthusiastic Party loyalist who is nonetheless eventually destroyed by the system he serves","He is a member of the Inner Party","He is Winston's boss"], ans:1, expl:"Parsons is a model Outer Party citizen, yet he is arrested after being denounced by his own daughter — showing no one is safe." },
    { q:"In 1984, what does the constant alteration of statistics by the Ministry of Plenty illustrate?", opts:["Genuine economic growth","The Party's manipulation of facts and figures to claim success despite actual scarcity and decline","Accurate economic reporting","A temporary wartime measure"], ans:1, expl:"The Ministry of Plenty announces increased rations even as actual conditions worsen — a clear example of doublethink and propaganda." },
    { q:"What broader warning does 1984 offer about technology?", opts:["Technology will always lead to a better society","Technology, when controlled entirely by a totalitarian state, can become a tool of total surveillance and oppression","Technology has no role in politics","Technology will inevitably overthrow tyranny"], ans:1, expl:"The telescreen exemplifies Orwell's warning: technology is not neutral — in the hands of a totalitarian state it enables unprecedented control." },
    { q:"How does the relationship between Winston and his mother (in his memories) function in the novel?", opts:["It shows the Party encourages strong family memories","It represents a lost world of genuine human tenderness and loyalty that the Party has destroyed","It is irrelevant to the novel's themes","It shows his mother was a Party loyalist"], ans:1, expl:"Winston's fragmented memories of his mother's self-sacrificing love contrast sharply with the loveless, suspicious relationships fostered by the Party." },
    { q:"What is the significance of the title 'Nineteen Eighty-Four' being written out in words rather than numerals in many editions?", opts:["It has no particular significance","Some critics note it slows the reader, emphasising the date as a concept rather than just a year, though Orwell's original title used numerals (1984)","It was a printing error","It changes the meaning of the novel entirely"], ans:1, expl:"While a minor stylistic point, the choice between '1984' and 'Nineteen Eighty-Four' has been discussed by critics regarding how the date is perceived by readers." },
    { q:"What is the 'Hate Week' event in 1984?", opts:["A week of mourning for fallen soldiers","An annual propaganda event whipping up public hatred against the Party's current enemy","A week when citizens are allowed to criticise the Party","A religious holiday"], ans:1, expl:"Hate Week is a large-scale propaganda spectacle, similar to the Two Minutes Hate but on a national scale, reinforcing enemy hatred and Party loyalty." },
    { q:"How does the sudden switch of Oceania's enemy during Hate Week (from Eurasia to Eastasia) demonstrate Party control?", opts:["It shows the Party makes mistakes","The population and records instantly adjust as if the new alignment had always been true, showing total control over perceived reality","It causes a public uprising","It is quietly ignored by everyone"], ans:1, expl:"The seamless, unquestioned switch — with records altered retroactively — shows the Party's power to make the population accept any version of reality." },
    { q:"What does Winston's statement that 'freedom is the freedom to say that two plus two make four' represent?", opts:["A mathematical error","The basic, minimal definition of intellectual freedom — the ability to recognise objective truth independent of authority","A Newspeak slogan","A statement of loyalty to the Party"], ans:1, expl:"For Winston, true freedom begins with the ability to perceive and state objective facts, even simple ones, without state interference." },
    { q:"What is the overall tone of Animal Farm compared to 1984?", opts:["Animal Farm is a lighter, fable-like satire while 1984 is a bleaker, more directly disturbing dystopia","Both have identical tones","Animal Farm is more violent and graphic than 1984","1984 is comic while Animal Farm is tragic"], ans:0, expl:"Animal Farm's fable form and animal characters create ironic distance and humour despite its dark themes, while 1984's realism makes its horrors more immediate." },
    { q:"What does the phrase 'thoughtcrime' encompass in 1984?", opts:["Only violent actions against the Party","Any independent thought, however small, that deviates from Party orthodoxy — even an unconscious facial expression can be 'facecrime'","Crimes committed by foreigners","Crimes that have not yet been planned"], ans:1, expl:"Thoughtcrime criminalises the mind itself — even involuntary reactions like a facial twitch ('facecrime') can be evidence of disloyalty." },
    { q:"What is the relationship between Winston and his former wife Katharine?", opts:["A passionate, loving marriage","A loveless union focused only on producing children for the Party, which they ultimately failed to do and separated","A secret political alliance","A marriage that ended in her execution"], ans:1, expl:"Katharine viewed sex purely as a duty to the Party; their incompatibility and lack of children led to their separation — though divorce is discouraged, not banned." },
    { q:"How does Orwell present the concept of 'reality control' in 1984?", opts:["As a minor plot detail","As the Party's ultimate goal — controlling not just behaviour and speech but perception of reality itself, summarised in the term 'doublethink'", "As something only the proles experience","As a temporary wartime policy"], ans:1, expl:"Reality control (or 'collective solipsism') means the Party determines what is real by controlling what people perceive, remember and believe." },
    { q:"What is the significance of Winston working in the 'Records Department' specifically?", opts:["It shows he has no real job","It places him at the very heart of the Party's falsification of history, giving him direct insight into how 'truth' is manufactured","It means he has access to weapons","It means he is part of the Inner Party"], ans:1, expl:"Winston's role gives the reader (and Winston) first-hand experience of how thoroughly and routinely the Party rewrites the past." },
    { q:"What broader literary tradition does Animal Farm belong to, in terms of form?", opts:["The Gothic novel","The political fable / beast fable, in the tradition of Aesop and Swift","The epistolary novel","The detective novel"], ans:1, expl:"Animal Farm uses talking animals to satirise human politics, following a long tradition from Aesop's fables to Swift's Gulliver's Travels." },
    { q:"What does the absence of any character who successfully resists the Party in 1984 suggest about Orwell's purpose?", opts:["Orwell believed resistance was easy","Orwell intended the novel as a warning of what could happen if totalitarianism were allowed to fully consolidate, not a prediction of inevitable doom","Orwell supported the Party's methods","The novel is incomplete"], ans:1, expl:"By showing total defeat, Orwell warns readers of the stakes — urging vigilance against totalitarian tendencies before they become unstoppable." },
    { q:"What is the function of the proles' culture (football pools, popular songs) in 1984?", opts:["It represents genuine cultural achievement","It shows how trivial pleasures can pacify a population and divert attention from political consciousness","It is evidence of prole rebellion","It is banned by the Party"], ans:1, expl:"The proles' absorption in lotteries and popular entertainment exemplifies how distraction can substitute for political awareness — a 'bread and circuses' effect." },
    { q:"How does the setting of Victory Mansions (Winston's apartment building) reflect broader themes of the novel?", opts:["It represents luxury and Party privilege","Its decay, broken lift and pervasive surveillance (telescreen, posters of Big Brother) reflect the grim material conditions and omnipresent control of daily life","It is a symbol of hope","It is located outside Party control"], ans:2, expl:"Victory Mansions' shabby, decaying state and the ever-present 'BIG BROTHER IS WATCHING YOU' poster set the oppressive tone of everyday life in Oceania." },
    { q:"What is the ultimate effect of O'Brien's torture methods on Winston's relationship with Julia?", opts:["It strengthens their bond permanently","Winston eventually betrays Julia by wishing the rats would attack her instead of him, destroying their relationship","Julia rescues Winston","They escape together"], ans:1, expl:"Under unbearable torture in Room 101, Winston's love for Julia is destroyed — he begs for her to suffer instead, completing his psychological breaking." },
    { q:"What does the phrase 'Who controls the past controls the future; who controls the present controls the past' mean in context?", opts:["It is a meaningless Party slogan","It explains the Party's strategy: by controlling current records and memory, it can shape both historical narrative and future belief","It refers to time travel","It is a statement made only by Winston, rejected by the Party"], ans:1, expl:"This Party maxim, which Winston copies into his diary, captures the logic behind the Ministry of Truth's constant falsification of records." },
    { q:"What is notable about the genre classification of both Animal Farm and 1984 as 'satire'?", opts:["Satire means they are purely comic with no serious message","Despite using fictional/fantastical elements, both works critique real political systems and human behaviour through exaggeration and irony","Satire means the works are historically inaccurate","Satire means the works avoid all political commentary"], ans:1, expl:"Satire uses irony, exaggeration and fictional frameworks to expose and criticise real-world politics and human folly — central to both works' purpose." },
    { q:"How does Orwell's background (Eton-educated but working as a colonial policeman in Burma) inform his writing?", opts:["It had no influence on his work","His experience enforcing British imperial rule gave him direct insight into how power, propaganda and coercion function — informing his anti-authoritarian themes","He wrote only about colonial Burma","It made him a supporter of empire"], ans:1, expl:"Orwell's essay 'Shooting an Elephant' and novel Burmese Days reflect his disillusionment with imperialism, which fed into his broader critique of abusive power in 1984 and Animal Farm." },
    { q:"What is the significance of Winston's act of betrayal under torture being something the Party already expected?", opts:["The Party is surprised by Winston's betrayal","O'Brien deliberately orchestrates events to ensure Winston reaches this point — showing the Party's total psychological mastery, not a personal failing unique to Winston","The betrayal was accidental","Winston was never actually tortured"], ans:1, expl:"O'Brien's calm, methodical approach reveals that breaking Winston completely — including destroying his love for Julia — is the Party's deliberate, achievable goal for any individual." },
    { q:"What does the recurring motif of glass (the paperweight, clear thought) suggest in 1984?", opts:["Glass represents Party technology","Fragility and transparency — the paperweight symbolises a fragile connection to a clearer, more authentic past that is easily shattered","Glass represents wealth","Glass has no symbolic meaning"], ans:1, expl:"The coral paperweight, shattered when Winston and Julia are arrested, symbolises the fragile, doomed nature of their private world of truth and feeling." },
    { q:"In what way does 1984 critique not just communism but any form of total power?", opts:["It critiques only Stalinist Russia and nothing else","Orwell deliberately created a fictional Party with no clear left/right ideology, emphasising that the hunger for power for its own sake transcends political labels","It critiques only capitalism","It has no broader critique beyond the USSR"], ans:1, expl:"Orwell stated the Party's ideology is essentially 'Ingsoc' (English Socialism) in name only — the novel's true subject is the corrupting nature of power itself, applicable to any regime." },
    { q:"What is the role of children's denunciations of parents as depicted through the Parsons family, in relation to historical totalitarian regimes?", opts:["It is purely fictional with no historical basis","It reflects real practices in regimes like Stalin's USSR and Nazi Germany, where youth organisations encouraged reporting disloyal family members","It shows children are protected from politics","It represents a Party policy that ultimately failed"], ans:1, expl:"Orwell drew on real historical precedents of state-sponsored youth informants to depict how totalitarianism can corrupt even the family unit." },
    { q:"What does the ambiguous fate of the Brotherhood (real or invented) contribute to the novel's atmosphere of paranoia?", opts:["It resolves all uncertainty for the reader","It leaves both Winston and the reader unable to distinguish genuine resistance from Party traps, mirroring the impossibility of trust in a surveillance state","It proves the Brotherhood is definitely real","It has no effect on the novel's atmosphere"], ans:1, expl:"The uncertainty over the Brotherhood's existence reinforces the novel's central horror: in a total surveillance state, no one — not even fellow dissidents — can be trusted." },
    { q:"How does the structure of Animal Farm's narrative pace (years passing quickly) affect its impact as an allegory?", opts:["It makes the story feel rushed and ineffective","The rapid passage of time compresses decades of Soviet history into a short narrative, emphasising the inevitability and speed of ideological betrayal","It has no effect on the allegory","It slows down to focus only on a single day"], ans:1, expl:"By compressing years into a short fable, Orwell highlights the pattern of revolutionary betrayal as almost mechanical and inevitable once power is concentrated." },
    { q:"What is the significance of Orwell choosing animals (rather than humans) as characters in Animal Farm?", opts:["It was purely for children's entertainment","Animal characters create ironic distance, allow universal/timeless application of the satire, and make the corruption of 'natural' hierarchies more starkly visible","Animals were easier to write about","It avoided any political meaning"], ans:1, expl:"By using animals, Orwell universalises his critique beyond a specific historical moment and highlights the absurdity and tragedy of the pigs' betrayal of 'animalism'." },
    { q:"What is the ultimate fate of Snowball in Animal Farm, and what does it represent historically?", opts:["He becomes the farm's leader","He is driven off the farm by Napoleon's dogs and becomes a scapegoat blamed for all problems — representing Trotsky's exile and vilification by Stalin","He retires peacefully","He is celebrated as a hero throughout"], ans:1, expl:"Snowball's expulsion and subsequent use as a scapegoat for every farm problem mirrors Stalin's propaganda campaign against the exiled Trotsky." },
    { q:"How do the Seven Commandments in Animal Farm change over the course of the novel, and what does this represent?", opts:["They remain exactly the same throughout","They are gradually altered (e.g. 'No animal shall sleep in a bed with sheets') to justify the pigs' increasing privileges, representing the corruption of revolutionary principles","They are added to by all animals equally","They are abolished entirely from the start"], ans:1, expl:"The pigs secretly amend the commandments to permit their own comfort and excess, illustrating how revolutionary ideals are eroded to serve those in power." },
    { q:"What does the final image of Animal Farm — animals unable to distinguish pigs from humans — most directly echo from earlier in the novel?", opts:["Old Major's original vision of equality, now completely inverted","The windmill's construction","Boxer's work ethic","The Battle of the Cowshed"], ans:0, expl:"Old Major's dream was that animals would never become like the oppressive humans — the ending shows this dream has been entirely betrayed." },
    { q:"What is the significance of the title 'Animal Farm: A Fairy Story'?", opts:["It indicates the book is intended only for young children","The ironic subtitle signals that, like a fairy tale, the story carries a deeper moral and political message beneath its simple surface","It means the story has a happy ending","It refers to a specific fairy tale Orwell was adapting"], ans:1, expl:"The subtitle 'A Fairy Story' is deeply ironic — the simple animal-fable form delivers a serious and bleak political allegory." }
  );

  /* ══ MARY SHELLEY (+85) ══ */
  window.QUIZ_DATA.shelley.push(
    { q:"What is the name of Victor Frankenstein's childhood friend who later dies at the Creature's hands?", opts:["Henry Clerval","Robert Walton","Alphonse Frankenstein","William Frankenstein"], ans:0, expl:"Henry Clerval, Victor's devoted friend, is murdered by the Creature in Ireland, deepening Victor's guilt." },
    { q:"Who is the first victim of the Creature in the novel?", opts:["Elizabeth Lavenza","William Frankenstein, Victor's young brother","Henry Clerval","Justine Moritz"], ans:1, expl:"The Creature strangles young William, Victor's brother, partly out of rage at being rejected and partly to harm Victor." },
    { q:"Who is wrongly executed for William's murder?", opts:["Henry Clerval","Justine Moritz, the family's servant","Elizabeth Lavenza","Robert Walton"], ans:1, expl:"Justine is falsely convicted and executed, adding to Victor's burden of guilt since he knows the true culprit." },
    { q:"Who does Victor marry in the novel?", opts:["Justine Moritz","Elizabeth Lavenza, his adopted cousin","Margaret Saville","Agatha De Lacey"], ans:1, expl:"Elizabeth Lavenza, raised alongside Victor as a sister-figure, becomes his bride — and is murdered by the Creature on their wedding night." },
    { q:"What happens to Elizabeth on her wedding night?", opts:["She runs away with another man","She is murdered by the Creature in revenge for Victor's refusal to make a companion","She dies of illness","She gives birth"], ans:1, expl:"The Creature kills Elizabeth as the ultimate act of revenge after Victor destroys the female creature he had begun." },
    { q:"What family does the Creature secretly observe and learn from?", opts:["The Frankenstein family","The De Lacey family in their cottage","The Walton family","The Clerval family"], ans:1, expl:"Hiding near their cottage, the Creature learns language, reading and human emotion by observing the De Laceys." },
    { q:"What books does the Creature read that shape his understanding of humanity?", opts:["The Bible, a dictionary, and a cookbook","Paradise Lost, Sorrows of Werter, and Plutarch's Lives","Shakespeare's complete works","Newspaper articles only"], ans:1, expl:"These three books — found in an abandoned satchel — give the Creature his framework for understanding good, evil, ambition and despair." },
    { q:"How does the Creature react to seeing his own reflection for the first time?", opts:["He is pleased with his appearance","He is horrified, realising he is hideous and will be shunned","He feels nothing","He believes it is another creature"], ans:1, expl:"Seeing his reflection in a pool, the Creature understands for the first time why people flee from him in terror." },
    { q:"What is the significance of the blind father in the De Lacey family (old Mr De Lacey)?", opts:["He represents Victor's father","He is the only human who treats the Creature kindly, because he cannot see his appearance","He is a minor irrelevant character","He recognises the Creature immediately as a monster"], ans:1, expl:"Old De Lacey, being blind, judges the Creature by his words and manner alone — showing that the Creature's monstrosity is purely a matter of appearance and society's reaction." },
    { q:"What does Victor do with the materials for the female creature?", opts:["He completes her and lets her live with the original Creature","He destroys his work before completion, breaking his promise to the Creature","He gives her to Walton","He sells the materials"], ans:1, expl:"Fearing a race of monsters, Victor destroys the unfinished female creature, provoking the Creature's vow of revenge." },
    { q:"Where does Victor travel to work on the female creature?", opts:["Geneva","Ingolstadt","A remote part of Scotland and the Orkney Islands","Paris"], ans:2, expl:"Victor isolates himself on a remote Scottish island to continue his forbidden experiments away from prying eyes." },
    { q:"What is Robert Walton's role in the novel?", opts:["He is Victor's brother","He is an Arctic explorer who rescues Victor and to whom Victor narrates his story","He is the Creature's creator","He is a doctor who treats Victor"], ans:1, expl:"Walton, seeking the North Pole, finds Victor near death on the ice; the novel is framed as Walton's letters to his sister Margaret." },
    { q:"What parallel exists between Victor Frankenstein and Robert Walton?", opts:["Both are doctors","Both are driven by dangerous, all-consuming ambition that risks their own lives and those of others","Both are married","Both are scientists studying electricity"], ans:1, expl:"Walton's obsessive quest for Arctic glory mirrors Victor's obsessive quest for the secret of life — both pursue ambition at great cost." },
    { q:"What ultimately happens to Victor at the end of the novel?", opts:["He successfully destroys the Creature and lives happily","He dies aboard Walton's ship, still pursuing the Creature","He reconciles with the Creature","He returns to Geneva and retires"], ans:1, expl:"Weakened by his pursuit of the Creature across the Arctic, Victor dies on Walton's ship, his quest unfulfilled." },
    { q:"What does the Creature do after Victor's death?", opts:["He celebrates his victory","He expresses remorse and announces his intention to end his own life","He returns to the De Lacey family","He demands Walton create him a companion"], ans:1, expl:"The Creature, grieving over Victor's body, expresses guilt for his crimes and vows to immolate himself in the Arctic wastes." },
    { q:"What scientific theory of the time influenced Shelley's depiction of reanimation?", opts:["Evolution by natural selection","Galvanism — the idea that electricity could animate dead tissue","Germ theory of disease","Quantum mechanics"], ans:1, expl:"Galvanism, based on Luigi Galvani's experiments making frog muscles twitch with electricity, inspired the novel's vague account of how Victor animates the Creature." },
    { q:"How does the novel depict the process of the Creature's creation?", opts:["In vivid scientific detail","Deliberately vaguely — Victor refuses to reveal the specifics, calling the knowledge too dangerous to share","As a magical, supernatural event","As a collaborative team effort"], ans:1, expl:"Shelley deliberately withholds technical detail, keeping the focus on the moral and emotional consequences rather than the science itself." },
    { q:"What is the effect of the epistolary/frame narrative structure on the reader's perception of truth?", opts:["It makes the story feel more objective","It creates layers of subjectivity, making the reader question each narrator's reliability and bias","It has no effect on the story","It proves the Creature's account is false"], ans:1, expl:"Because the story passes through Walton, then Victor, then the Creature, the reader receives a heavily filtered, multiply-subjective account." },
    { q:"What does Victor's isolation during his experiments suggest about his character?", opts:["He is sociable and collaborative","His secrecy and isolation reflect an unhealthy, obsessive ambition that cuts him off from family, friends and moral responsibility","He is forced into isolation by his family","He works in isolation because of poverty"], ans:1, expl:"Victor's withdrawal from human relationships while pursuing his experiment foreshadows the destructive consequences of unchecked ambition." },
    { q:"What is the significance of the Creature's lack of a name?", opts:["It shows he is unimportant","His namelessness (often mistakenly called 'Frankenstein') reflects his lack of identity, origin and place in human society","Shelley simply forgot to name him","It indicates he is a robot, not a living being"], ans:1, expl:"The Creature has no name, no family and no species — his namelessness embodies his fundamental alienation." },
    { q:"How does the novel explore the theme of nature versus nurture?", opts:["It argues entirely for nature — the Creature is evil from birth","The Creature is born benevolent but becomes vengeful only after repeated rejection and cruelty — suggesting nurture/environment shapes character","It does not address this theme","It argues the Creature was always evil"], ans:1, expl:"The Creature's transformation from gentle to vengeful directly results from society's treatment of him, raising questions about the origins of evil." },
    { q:"What does Victor's reaction upon first seeing his completed Creature reveal?", opts:["Joy and pride at his achievement","Immediate horror and disgust — he flees, abandoning his creation without taking responsibility","Curiosity but no strong emotion","Love, as if for a son"], ans:1, expl:"Victor's instant rejection of the Creature — based purely on its appearance — sets in motion the tragedy, as the abandoned Creature seeks revenge for this neglect." },
    { q:"What is the role of letters in the novel's structure?", opts:["Letters play no role","Walton's letters to his sister Margaret frame the entire narrative, situating Victor's story within another story","Only Victor writes letters","The Creature communicates only by letter"], ans:1, expl:"The novel begins and ends with Walton's letters, which contain Victor's narrated story, which itself contains the Creature's narrated story." },
    { q:"What does Mary Shelley's depiction of motherhood/creation without a mother suggest?", opts:["It celebrates traditional motherhood","Victor's 'creation' bypasses natural birth and a mother figure entirely, raising questions about the consequences of life created outside natural/social bonds","It has no relevance to gender","It depicts a perfect family structure"], ans:1, expl:"Critics note that Victor's solitary 'birth' of the Creature, without a mother, results in a being with no nurturing, no family bonds and no place in society." },
    { q:"How does the novel use the contrast between the Arctic and the Swiss Alps as settings?", opts:["Both settings represent comfort and safety","Both represent sublime, extreme, and dangerous landscapes that mirror the characters' extreme passions and isolation","The Arctic represents civilization","The Alps represent urban life"], ans:1, expl:"Both the icy Arctic (Walton/Victor's final pursuit) and the sublime Alps (where Victor confronts the Creature) are vast, hostile landscapes reflecting the characters' isolation and extremity." },
    { q:"What does the Creature request of Victor when they meet on the glacier?", opts:["To be destroyed immediately","To hear Victor's story and then to have Victor create a companion for him","Money and shelter","To be taken to a hospital"], ans:1, expl:"The Creature persuades Victor to listen to his story, then demands a female companion to ease his loneliness — a demand Victor initially agrees to, then breaks." },
    { q:"What is the 'monster' actually referred to as by Mary Shelley in the text?", opts:["Frankenstein","Various terms such as 'creature', 'wretch', 'daemon', 'fiend' — never given a proper name","Adam","Prometheus"], ans:1, expl:"Shelley uses a range of charged terms but never a proper name — 'Frankenstein' properly refers only to Victor and his family." },
    { q:"How does the novel critique the pursuit of knowledge without ethical consideration?", opts:["It fully endorses unrestricted scientific pursuit","Victor's tragedy results from pursuing forbidden knowledge without considering the moral responsibilities and consequences of his creation","It argues science should be banned entirely","It has no view on the ethics of science"], ans:1, expl:"Frankenstein is often read as an early warning about science pursued without ethical responsibility for its consequences — a theme still relevant to bioethics and AI debates today." },
    { q:"What does Victor's family background (wealthy Genevan family) contribute to the novel?", opts:["It is irrelevant detail","It establishes Victor's comfortable, loving upbringing, making his later isolation and the destruction of his family especially tragic","It shows Victor was always poor","It explains his scientific genius"], ans:1, expl:"Victor's loving family (contrasted with the Creature's lack of one) makes the destruction of that family by the Creature a devastating irony." },
    { q:"What is the significance of the name 'Prometheus' in the subtitle beyond the theft of fire?", opts:["It only refers to fire-stealing","Prometheus also shaped humans from clay in some myths, paralleling Victor's act of creating life — and both face severe punishment for transgressing natural/divine boundaries", "It refers to a Greek city","It has no further significance"], ans:1, expl:"In some versions of the myth, Prometheus creates humanity from clay — directly paralleling Victor's creation of the Creature, with both 'creators' suffering for their transgression." },
    { q:"How is the theme of revenge developed through both Victor and the Creature?", opts:["Only the Creature seeks revenge","Both characters become consumed by mutual revenge — the Creature for his abandonment, and Victor for the murders of his loved ones — destroying both of them", "Neither character seeks revenge","Revenge is resolved peacefully early in the novel"], ans:1, expl:"The cycle of revenge between creator and creation escalates until both are destroyed, illustrating how vengeance consumes everyone involved." },
    { q:"What does the Creature's eloquence and intelligence challenge about traditional 'monster' narratives?", opts:["Nothing — he behaves exactly as expected of a monster","It challenges the assumption that monstrousness is inherent; the Creature is articulate, philosophical and capable of profound feeling, complicating simple notions of good and evil","It proves he is not really a monster at all and causes no harm","It shows he was created with a human brain"], ans:1, expl:"The Creature's articulate self-narration forces readers to sympathise with him, undermining simplistic categorisations of monster versus human." },
    { q:"What is Victor's emotional state throughout most of the novel after creating the Creature?", opts:["Calm and content","Wracked with guilt, fear, and physical/mental illness as a result of his actions and their consequences","Joyful and proud","Indifferent"], ans:1, expl:"Victor suffers repeated nervous breakdowns and illnesses, reflecting the psychological toll of guilt and fear of the Creature's revenge." },
    { q:"How does the novel use multiple narrators to develop sympathy for different characters?", opts:["It uses only one narrator throughout","Each narrator (Walton, Victor, the Creature) gets to present their perspective and justify their actions, creating a complex, multi-sided moral picture","Sympathy is directed only at Victor","The Creature's perspective is never presented"], ans:2, expl:"By giving the Creature his own extended first-person narrative, Shelley ensures readers understand his perspective and suffering, not just Victor's." },
    { q:"What does the destruction of the female creature suggest about Victor's view of female agency/sexuality?", opts:["Victor fully supports the female creature's independence","Some critics argue Victor's fear of an uncontrollable female creature reflects broader anxieties about female autonomy and reproduction","It has no connection to gender themes","Victor creates the female creature successfully"], ans:1, expl:"Feminist critics have read Victor's destruction of the female creature — fearing she might refuse to obey the male Creature or 'breed' uncontrollably — as reflecting period anxieties about female agency." },
    { q:"How does Mary Shelley's novel relate to the Romantic fascination with the sublime?", opts:["It rejects the sublime entirely, favouring domestic settings","The novel repeatedly places characters before overwhelming natural forces (glaciers, storms, the Arctic) that evoke awe and terror, key Romantic sublime experiences","It is set entirely indoors","The sublime appears only in the novel's final chapter"], ans:1, expl:"From the Alps to the Arctic, Shelley's landscapes evoke the Romantic sublime — vast, powerful nature that dwarfs and overwhelms human characters." },
    { q:"What is the role of secrecy in Frankenstein?", opts:["Secrecy plays no role","Victor's secrecy about his experiment and its results isolates him and prevents anyone from helping him manage the consequences, deepening the tragedy","Secrecy protects Victor from all harm","Only the Creature keeps secrets"], ans:1, expl:"Victor's refusal to confide in anyone — even when Justine is wrongly executed — compounds his guilt and isolates him from possible solutions." },
    { q:"How does the novel's setting move across Europe, and what might this signify?", opts:["It stays in one location throughout","The action spans Geneva, Ingolstadt, England, Scotland, Ireland and the Arctic — reflecting both Romantic interest in travel/exploration and the characters' restless, unsettled state of mind","It is set entirely in America","It is set in a single fictional country"], ans:1, expl:"The wide-ranging European and Arctic settings reflect Romantic-era fascination with travel and exploration, as well as the characters' inner turmoil and flight from consequences." },
    { q:"What does Victor mean when he calls himself the 'modern Prometheus'?", opts:["He believes he is a god","He acknowledges he has overstepped natural boundaries by creating life, like Prometheus's theft of fire, and anticipates punishment","He is comparing himself to a politician","He believes he will be rewarded for his discovery"], ans:1, expl:"The comparison frames Victor's act as a transgression against natural order for which, like Prometheus, he must suffer eternally." },
    { q:"What is notable about the publication history of Frankenstein in 1818?", opts:["It was published under Mary Shelley's name immediately","It was published anonymously, leading many to assume Percy Shelley was the author","It was banned upon publication","It was an instant bestseller credited to Lord Byron"], ans:1, expl:"The 1818 edition was published anonymously with a preface by Percy Shelley, leading many readers to assume he was the author — Mary Shelley was credited only in the 1831 edition." },
    { q:"What changes were made in the 1831 revised edition of Frankenstein?", opts:["No changes were made","Shelley added a new introduction and made Victor's fate feel more predetermined, emphasising destiny over free will","The ending was changed to a happy one","The Creature was given a name"], ans:1, expl:"The 1831 edition includes Mary Shelley's famous introduction describing the novel's origin and subtly shifts the tone toward fatalism." },
    { q:"How does Frankenstein engage with contemporary debates about the origin of life ('vitalism' debate)?", opts:["It ignores all scientific debate","It reflects the early 19th-century debate between vitalists (who believed life required a special 'vital force') and materialists (who believed life was purely chemical/electrical)","It only discusses religious creation","It predates all scientific debate on life"], ans:1, expl:"The Abernethy-Lawrence vitalism debate, which Percy Shelley followed closely, forms part of the intellectual background to Victor's experiments." },
    { q:"What is the significance of Victor falling ill multiple times throughout the novel?", opts:["It shows he has a weak constitution unrelated to the plot","His recurring illnesses, often following traumatic events, externalise his psychological guilt and the physical toll of his secret","Illness is used only for comic relief","It shows the Creature is poisoning him"], ans:1, expl:"Victor's breakdowns and fevers function almost as psychosomatic responses to guilt and trauma, blurring the line between physical and moral sickness." },
    { q:"What does the novel suggest about the responsibilities of a creator to their creation?", opts:["Creators have no responsibility once creation is complete","The novel strongly suggests that creators bear moral responsibility for the wellbeing and consequences of what they create — Victor's failure to do so causes the tragedy","Creation automatically implies care, which Victor provides","The Creature should have cared for Victor instead"], ans:1, expl:"Victor's abandonment of his 'child'-like creation is presented as the originating moral failure of the entire tragedy." },
    { q:"How is the theme of alienation explored through the Creature?", opts:["The Creature is fully accepted by human society","The Creature's physical difference leads to total rejection by every human he encounters, driving him toward isolation, despair and eventually violence","The Creature chooses isolation voluntarily for no reason","Alienation is not a theme in the novel"], ans:1, expl:"Each rejection (by Victor, the De Laceys, villagers) deepens the Creature's alienation, illustrating how social rejection can transform a benevolent being." },
    { q:"What does Victor's confession to Walton on his deathbed serve to do?", opts:["It exonerates Victor of all guilt","It serves as a warning to Walton (and the reader) about the dangers of unchecked ambition, even as Victor's feelings about his own actions remain ambiguous","It reveals Victor was lying throughout","It has no narrative function"], ans:1, expl:"Victor urges Walton to abandon his dangerous Arctic quest, drawing an explicit parallel between their ambitions — though Victor's own regret remains complex and unresolved." },
    { q:"In what way does the novel function as an early example of Gothic science fiction?", opts:["It contains no Gothic elements","It combines Gothic atmosphere (graveyards, charnel houses, storms, isolation) with speculative scientific premises (reanimation), creating a hybrid genre","It is purely a romance novel","It is set in a fantasy world with no scientific basis"], ans:1, expl:"Frankenstein merges the dark, atmospheric conventions of Gothic fiction with speculative science — a combination that established it as a foundational science fiction text." },
    { q:"What is the relationship between Victor and his father, Alphonse Frankenstein?", opts:["Alphonse is abusive and neglectful","Alphonse is a loving, supportive father whose concern for Victor highlights what Victor risks losing through his obsession","Alphonse dies before Victor is born","Alphonse encourages Victor's experiments"], ans:1, expl:"Alphonse's love and eventual grief (he dies after Elizabeth's murder) underscore the human cost of Victor's secret pursuits." },
    { q:"How does Victor's narrative attempt to control the reader's sympathy?", opts:["Victor presents himself entirely as a villain","Victor frames himself largely as a victim of fate and the Creature's cruelty, often minimising his own responsibility for the tragedy","Victor refuses to tell his story at all","Victor's narrative is completely objective"], ans:1, expl:"Victor's self-justifying narration invites readers to question how much responsibility he bears versus how much he displaces onto the Creature and 'destiny'." },
    { q:"What does the Creature's statement that he was 'benevolent' before becoming 'miserable' suggest?", opts:["The Creature was always violent","The Creature's capacity for evil developed in response to suffering and rejection, not as an innate trait","The statement is a lie told to manipulate Victor","It suggests the Creature has no memory of his early days"], ans:1, expl:"This claim is central to the novel's exploration of whether evil is innate or created by circumstance and social treatment." },
    { q:"What broader social commentary might the Creature's exclusion represent, according to many critics?", opts:["No social commentary is intended","Critics have read the Creature's exclusion as commentary on the treatment of marginalised groups — the poor, the disabled, immigrants, or the racially 'othered' — based on appearance alone","It comments only on scientific ethics","It represents Mary Shelley's views on animal rights"], ans:1, expl:"The Creature's rejection based purely on appearance has invited many allegorical readings about prejudice and the treatment of those perceived as 'other'." },
    { q:"What is the function of Victor's two years of intense study and isolation at Ingolstadt before creating the Creature?", opts:["It shows Victor having a normal university experience","It depicts Victor's descent into obsessive isolation, cutting off correspondence with family and showing the warning signs of his coming tragedy","It shows Victor socialising extensively","It has no narrative purpose"], ans:1, expl:"Victor's increasing isolation and neglect of his health and relationships during this period foreshadow the destructive consequences of his obsession." },
    { q:"How does the novel use the image of fire/light in relation to knowledge?", opts:["Fire/light has no symbolic role","Fire and light (echoing Prometheus's stolen fire) symbolise dangerous knowledge — illuminating but also destructive when misused","Fire represents only physical warmth","Light represents the Creature's goodness only"], ans:1, expl:"The Promethean association of fire with both illumination (knowledge) and destruction (punishment) runs throughout the novel's themes." },
    { q:"What does Victor mean by saying 'I had been the author of unalterable evils'?", opts:["He is proud of his achievements","He recognises that his actions have caused irreversible harm to others, accepting (at least partially) his moral responsibility","He is referring to a book he wrote","He believes the evils were caused by someone else"], ans:1, expl:"This admission reflects Victor's recognition — though often inconsistent — of his culpability for the deaths caused indirectly by his creation." },
    { q:"How is the theme of ambition critiqued differently through Victor versus Walton?", opts:["Both are equally condemned with no distinction","Victor's ambition leads to total destruction, while Walton, having heard Victor's story, ultimately turns back from his Arctic quest — suggesting ambition can be checked through learning from others' mistakes","Walton's ambition is celebrated as heroic","Neither character displays ambition"], ans:1, expl:"Walton's decision to abandon his expedition after hearing Victor's story offers a glimmer of hope that destructive ambition can be tempered by wisdom." },
    { q:"What does the absence of any religious redemption for Victor at the end suggest?", opts:["Victor is saved and goes to heaven","Victor dies without clear absolution or redemption, reinforcing the novel's bleak view of the consequences of his transgression","The novel ends with a religious miracle","Victor converts to a new religion"], ans:1, expl:"Victor's unresolved death, still pursuing the Creature, denies the reader a neat moral resolution or redemption arc." },
    { q:"What is the critical significance of the phrase 'I, the miserable and the abandoned' spoken by the Creature?", opts:["It shows the Creature's pride in his strength","It emphasises the Creature's profound loneliness and his self-identification as a victim of abandonment, central to the novel's exploration of parental/creator responsibility","It is a boast about his power","It refers to his physical illness"], ans:1, expl:"The Creature's self-description as 'abandoned' directly indicts Victor's failure as a creator/parent figure." },
    { q:"How does the novel's treatment of the Creature's eloquence compare to popular film depictions (e.g. Boris Karloff's portrayal)?", opts:["They are identical","The novel's Creature is highly articulate and philosophical, in stark contrast to the mute, grunting monster of many film adaptations","Film adaptations are always more faithful to the novel","The novel never shows the Creature speaking"], ans:1, expl:"Many film versions strip the Creature of speech and complexity, losing the novel's central tension between his eloquence and his monstrous appearance." },
    { q:"What does the structure of 'frame narratives within frame narratives' in Frankenstein achieve thematically?", opts:["It simplifies the moral message into a single viewpoint","It mirrors the novel's themes of creation and responsibility — each narrator 'creates' the next narrative, just as Victor creates the Creature","It has no thematic resonance","It confuses readers without purpose"], ans:1, expl:"Critics note the layered narration ('stories within stories') as a structural echo of the novel's central concern with creation, responsibility and inheritance." },
    { q:"Why might Mary Shelley have chosen a male scientist as her protagonist rather than a female one?", opts:["She had no choice in the matter","Science and pursuit of forbidden knowledge were coded as masculine domains in her era, allowing Shelley to critique masculine ambition and its exclusion of female/domestic values","Female scientists were common in her era","The novel originally had a female protagonist"], ans:1, expl:"By focusing on a male scientist who bypasses female reproduction entirely, Shelley critiques a masculine pursuit of 'creation' that excludes traditionally feminine, nurturing roles — with disastrous results." },
    { q:"What is the effect of the Creature learning of his 'creation' through Victor's abandoned laboratory notes?", opts:["The Creature feels grateful to Victor","The Creature feels horror and revulsion at his own origins, having no positive narrative of his creation to draw on","The notes give the Creature happy memories","The Creature cannot read the notes"], ans:1, expl:"Reading Victor's notes, which describe his disgust during the Creature's creation, deepens the Creature's sense of being an unwanted, 'cursed' origin." },
    { q:"How does weather/climate function symbolically in Frankenstein?", opts:["Weather is purely incidental with no symbolic function","Storms, lightning and extreme cold often accompany pivotal emotional and plot moments, reflecting turmoil and foreshadowing disaster","Weather is always calm and pleasant","Weather only appears in the final chapter"], ans:1, expl:"Lightning accompanies key moments (e.g. Victor's realisation about reanimation after witnessing a storm), linking natural forces to the novel's themes of power and destruction." },
    { q:"What does the term 'doppelganger' (double) suggest about the relationship between Victor and the Creature?", opts:["They are unrelated characters with no connection","Many critics read the Creature as Victor's psychological double — representing his repressed, monstrous side, born from his own ambition","The term has no relevance to the novel","Victor and the Creature are literally twins"], ans:1, expl:"The doppelganger reading frames the Creature as an externalisation of Victor's own destructive impulses — they pursue, mirror and ultimately destroy each other." },
    { q:"What is ironic about Victor's reason for creating the Creature in the first place?", opts:["He wanted to help humanity through medical breakthroughs and was honoured for it","He wanted to conquer death and be revered as a god-like benefactor of a 'new species', yet his creation brings only death and his own ruin","He created the Creature by accident with no intention","His intentions were purely evil from the start"], ans:1, expl:"Victor's grandiose vision of a grateful 'new species' that would bless him as their creator is utterly inverted — his creation curses and destroys him instead." },
    { q:"How does the novel address the limits of human knowledge and the dangers of 'playing God'?", opts:["It celebrates humans surpassing natural limits without consequence","The novel suggests that overstepping the natural boundaries of human knowledge and power — 'playing God' — leads to suffering disproportionate to any benefit gained","It argues humans should pursue unlimited knowledge regardless of consequences","It has no view on human limitations"], ans:1, expl:"The 'playing God' theme remains one of the most enduring interpretations of Frankenstein, applied to debates from cloning to artificial intelligence." },
    { q:"What is the significance of the novel ending with the Creature disappearing into the Arctic darkness, 'lost in darkness and distance'?", opts:["It provides a clear, happy resolution","The ambiguous, open ending leaves the Creature's fate (and the moral questions he raises) unresolved, denying neat closure","It shows the Creature returns home triumphantly","It reveals the Creature was never real"], ans:1, expl:"The Creature's vanishing into darkness — rather than a confirmed death — leaves the novel's central questions about creation, responsibility and monstrosity deliberately unresolved." },
    { q:"How does the setting of Geneva, Switzerland, function in the novel?", opts:["It represents danger and chaos throughout","Geneva represents Victor's stable, happy home and family — a world of order and affection that is ultimately destroyed by the consequences of his ambition","It is the location of all the murders","It is never mentioned in the novel"], ans:1, expl:"Geneva, Victor's birthplace, anchors the novel's sense of a lost domestic idyll, contrasted with the wild, isolated settings of his transgressions." },
    { q:"What does the phrase 'I am thy creature' (spoken by the Creature to Victor) emphasise?", opts:["The Creature's independence from Victor","The Creature's claim on Victor as his maker, invoking an obligation of care that Victor has failed to honour — echoing language used of God and Adam","The Creature's desire to destroy Victor immediately","The Creature's denial of his own origins"], ans:1, expl:"The biblical echo (Adam addressing God) frames the Creature's appeal to Victor in terms of a creator's neglected duty toward his creation." },
    { q:"How might Frankenstein be read in relation to Mary Shelley's own experiences of loss (she lost several children)?", opts:["The novel has no connection to her personal life","Some critics connect the novel's preoccupation with creation, loss and grief to Mary Shelley's own experiences of childbirth, infant death and bereavement","Mary Shelley never experienced loss","The novel was written before any of her children were born"], ans:1, expl:"Biographical critics note that Shelley wrote Frankenstein after losing her first child, and the novel's anxieties about creation and loss may reflect this personal trauma." },
    { q:"What is the significance of Victor's claim that he 'worked hard for nearly two years, for the sole purpose of infusing life into an inanimate body'?", opts:["It shows the Creature was created instantly","It emphasises the immense time, dedication and obsessive focus required, underscoring how completely Victor sacrificed his health and relationships for this single goal","It shows Victor had help from a team","It shows Victor regretted starting the project from day one"], ans:1, expl:"The two years of secretive, obsessive labour establish the depth of Victor's monomania before the Creature even comes to life." },
    { q:"How does Mary Shelley use the contrast between domestic/family scenes and scenes of horror?", opts:["The novel contains no domestic scenes","Warm domestic scenes (the Frankenstein and De Lacey families) are juxtaposed with horror (murders, the Creature's suffering) to heighten the tragedy of destroyed innocence","Domestic and horror scenes never appear together","All scenes in the novel are equally horrific"], ans:1, expl:"The juxtaposition of loving family scenes with violent destruction emphasises what is lost through Victor's transgression and the Creature's revenge." },
    { q:"What does the Creature mean when he tells Victor 'You are my creator, but I am your master'?", opts:["The Creature is being literal about ownership","The Creature asserts that his power over Victor's emotions and fate (through fear and threat) has effectively reversed their relationship of creator and created","The Creature wants to take over Victor's scientific work","This line does not appear in the novel"], ans:1, expl:"This chilling reversal shows how the Creature, though created by and dependent on Victor's choices, has gained psychological power over his creator through terror." },
    { q:"In what way is Frankenstein considered a cautionary tale relevant to modern biotechnology debates?", opts:["It has no relevance to modern science","Its central questions — about the ethics of creating life, the responsibilities of creators, and unintended consequences — are frequently invoked in debates about genetic engineering, cloning and AI","It only applies to 19th-century chemistry","Modern scientists have proven Shelley's concerns groundless"], ans:1, expl:"The term 'Frankenfood' and references to 'playing God' in genetic engineering debates show the novel's continued cultural relevance to bioethics." },
    { q:"What is the significance of Victor describing his work as creating 'a new species' that would 'bless him as its creator'?", opts:["It shows Victor's purely altruistic and realistic expectations","It reveals Victor's grandiose, almost messianic ambitions — he imagines himself as a god-like figure to be worshipped, a fantasy entirely shattered by reality","It shows Victor expected the Creature to be small and harmless","It shows Victor planned to create only one being"], ans:1, expl:"Victor's fantasy of god-like adoration starkly contrasts with the horror, guilt and destruction that actually follow his creation." },
    { q:"How does the novel use the motif of pursuit/chase in its final chapters?", opts:["There is no pursuit in the novel","Victor's pursuit of the Creature across Europe and into the Arctic mirrors the earlier pursuit dynamic (Creature seeking Victor), now reversed, emphasising their mutual entrapment","The pursuit is entirely one-sided with no reversal","The pursuit ends quickly with Victor's capture of the Creature"], ans:1, expl:"The reversal of pursuer and pursued (the Creature originally sought Victor; now Victor chases the Creature) underscores their inescapable, mutually destructive bond." },
    { q:"What is the overall tone established by Mary Shelley's introduction to the 1831 edition?", opts:["Lighthearted and comedic","Reflective and somewhat melancholic, describing the novel's origins at Villa Diodati and Shelley's own creative process as a kind of 'birth'","Angry and politically charged","Purely technical, explaining scientific accuracy"], ans:1, expl:"Shelley's 1831 introduction reflects on her youth, her famous companions, and frames the novel's conception as her own act of creative 'birth' — paralleling the novel's themes." },
    { q:"How does Frankenstein engage with the idea of 'the family' as a social institution?", opts:["The novel ignores family entirely","The novel repeatedly shows family as the source of love, identity and moral grounding — and the Creature's tragedy stems largely from being denied any family", "Family is portrayed as entirely negative throughout","The Creature has a large supportive family"], ans:1, expl:"The contrast between Victor's loving family (later destroyed) and the Creature's complete lack of family/community underlines the novel's emphasis on belonging and connection." },
    { q:"What does the phrase 'the beautiful and the terrific' (used in descriptions of nature) reflect about Romantic aesthetics in the novel?", opts:["It reflects a purely classical aesthetic of order and symmetry","It reflects the Romantic fascination with the sublime, where beauty and terror coexist in overwhelming natural scenes","It refers only to the Creature's appearance","It has no aesthetic significance"], ans:1, expl:"This pairing of beauty and terror is a hallmark of the Romantic sublime, used throughout the novel's descriptions of mountains, storms and ice." },
    { q:"What broader question about identity does the Creature's situation raise — having no name, no family, and no species?", opts:["Identity is irrelevant to the novel","It raises the question of how identity is formed — through biology, society, relationships, or language — when none of the usual sources (family, species, name) are available","The Creature has a clear, stable identity from birth","The novel resolves this question definitively with a happy ending"], ans:1, expl:"The Creature's struggle to understand 'what' and 'who' he is — without any of the normal markers of identity — is central to the novel's exploration of selfhood." },
    { q:"How might the ending of Frankenstein be seen as cyclical rather than final?", opts:["The ending is completely conclusive with no ambiguity","Victor dies still pursuing the Creature, and the Creature disappears still grieving — the cycle of pursuit, loss and isolation seems set to continue without resolution","The Creature is captured and put on trial","Victor and the Creature reconcile fully before the end"], ans:1, expl:"Neither character achieves closure — Victor dies mid-pursuit, and the Creature vanishes to an uncertain fate, suggesting the destructive cycle they created has no true ending." },
    { q:"What is the significance of Victor's professor M. Waldman at Ingolstadt?", opts:["He discourages Victor from studying science","He inspires Victor's fascination with modern chemistry and the possibility of discovering 'life and death', encouraging the ambition that leads to the Creature","He is the only character who later helps Victor destroy the Creature","He is revealed to be the Creature in disguise"], ans:1, expl:"Waldman's lectures on the potential of modern science to penetrate the secrets of nature directly ignite Victor's obsessive ambition." },
    { q:"How does Victor describe his feelings immediately before animating the Creature?", opts:["Calm confidence and certainty of success","A mixture of anxious anticipation and a vague sense of dread about what he is about to do","Complete indifference","Joyful celebration with friends"], ans:1, expl:"Victor recalls 'breathless eagerness' mixed with unease, foreshadowing the horror that follows the Creature's animation." },
    { q:"What does Victor's collapse into a long illness immediately after creating the Creature represent?", opts:["A purely physical illness with no symbolic meaning","A psychological and physical breakdown brought on by horror and guilt, the first sign of the destructive toll his transgression will take","A celebration of his success","The Creature poisoning him"], ans:1, expl:"Victor's nervous fever, during which Clerval cares for him, marks the beginning of the psychological devastation that follows his act of creation." },
    { q:"Why does the Creature ultimately decide not to harm the De Lacey family despite his loneliness?", opts:["He is physically incapable of approaching them","He initially feels affection and gratitude toward them after secretly helping them, hoping for their friendship and acceptance","He is afraid of being caught by the police","He has already been banished from the area"], ans:1, expl:"The Creature secretly performs kind acts (gathering firewood) for the De Laceys, hoping to be accepted — his eventual rejection by them is especially devastating because of this hope." },
    { q:"What does the Creature's statement 'Cursed creator! Why did you form a monster so hideous that even you turned from me in disgust?' reveal about the source of his suffering?", opts:["His suffering is purely physical pain","His suffering originates primarily from rejection and the absence of love, beginning with his own creator's disgust, rather than from his strength or appearance alone","He blames only himself for his suffering","He feels no real suffering, only anger"], ans:1, expl:"This direct address to Victor places responsibility for the Creature's anguish squarely on the abandonment by his creator — the root of all that follows." }
  );

  /* ══ OSCAR WILDE (+85) ══ */
  window.QUIZ_DATA.wilde.push(
    { q:"What is the relationship between Dorian Gray and Lord Henry Wotton?", opts:["Lord Henry is Dorian's father","Lord Henry is a cynical mentor whose hedonistic philosophy corrupts the impressionable young Dorian","Lord Henry is Dorian's brother","Lord Henry is Dorian's servant"], ans:1, expl:"Lord Henry's witty, amoral philosophy of pleasure-seeking profoundly shapes — and ultimately corrupts — Dorian's worldview." },
    { q:"Who paints the portrait of Dorian Gray?", opts:["Lord Henry Wotton","Basil Hallward, an artist infatuated with Dorian's beauty","Dorian himself","Sybil Vane"], ans:1, expl:"Basil Hallward, who idolises Dorian's beauty, paints the fateful portrait that will absorb Dorian's sins." },
    { q:"What happens to Basil Hallward in the novel?", opts:["He moves to Paris","Dorian murders him after Basil sees the corrupted portrait","He becomes a successful art dealer","He marries Sybil Vane"], ans:1, expl:"When Basil confronts Dorian about his decadent reputation and sees the hideous portrait, Dorian kills him in a fit of rage." },
    { q:"Who is Sybil Vane?", opts:["Dorian's mother","A young actress whom Dorian briefly loves and whose suicide marks his first major moral failure","Lord Henry's wife","Basil's sister"], ans:1, expl:"Sybil, an actress Dorian initially adores for her artistic talent, kills herself after Dorian cruelly rejects her — the portrait shows its first change after this." },
    { q:"What is the first change that appears on the portrait of Dorian Gray?", opts:["It grows more beautiful","A cruel sneer appears on its lips after Dorian's callous treatment of Sybil Vane","It develops grey hair","It begins to fade entirely"], ans:1, expl:"After Dorian's cruelty causes Sybil's suicide, the portrait's expression subtly changes — the first sign of its supernatural connection to his soul." },
    { q:"How does Dorian hide the portrait as it becomes increasingly hideous?", opts:["He destroys it immediately","He locks it away in a locked room at the top of his house, visiting it secretly","He gives it to Basil","He sells it to a collector"], ans:1, expl:"Dorian conceals the increasingly monstrous portrait in a locked attic room, terrified anyone might discover his secret." },
    { q:"What is the significance of Dorian remaining eternally young while the portrait ages?", opts:["It shows scientific progress","It externalises the moral consequences of his hedonistic lifestyle, allowing him to escape visible punishment while his soul (the portrait) decays", "It is never explained in the novel","It shows Dorian has found a medical cure for aging"], ans:1, expl:"The portrait bears the physical marks of Dorian's sins and aging, while his actual body and face remain perfect — a Faustian bargain with no explicit devil." },
    { q:"What is Lord Henry's view on influence, as expressed in the novel?", opts:["Influence is always positive and necessary for growth","To influence a person is to give them one's own soul — Lord Henry sees this as an exciting, almost artistic act, regardless of consequences","Influence should always be resisted","Influence only works between equals"], ans:1, expl:"Lord Henry's theory of influence as a kind of artistic experimentation on another person's soul reflects his amoral aestheticism — and foreshadows his corrupting effect on Dorian." },
    { q:"What does Dorian do with the knife that he used to murder Basil?", opts:["He keeps it as a souvenir","He attempts to destroy evidence and later the same knife is used (offstage) when he stabs the portrait at the novel's end","He gives it to the police","He throws it into the Thames immediately and it is never mentioned again"], ans:1, expl:"The same knife Dorian used to kill Basil reappears symbolically at the end, when Dorian uses a knife to destroy the portrait — and himself." },
    { q:"What is Wilde's view on the relationship between art and the artist's life, as suggested by the novel's preface?", opts:["The artist's life and their art are always identical","Wilde suggests art exists independently of moral judgement of the artist — 'the artist is the creator of beautiful things'","Art should always reflect the artist's biography directly","Artists should be judged primarily on their morality"], ans:1, expl:"The preface's aphorisms establish Wilde's aesthetic position: art's value lies in beauty and craft, not in moral instruction or biographical truth." },
    { q:"What does the character of Lord Henry ultimately fail to do, despite his philosophy?", opts:["He fails to ever speak eloquently","He never actually acts on his hedonistic theories himself — he merely observes and influences others, including Dorian, from a safe distance","He fails to attend any social events","He fails to marry"], ans:1, expl:"Lord Henry is a theorist of hedonism but largely an observer — Dorian becomes the 'experiment' who actually lives out (and is destroyed by) Lord Henry's philosophy." },
    { q:"In The Importance of Being Earnest, what is revealed about Jack Worthing's true identity?", opts:["He is actually a foreign prince","He is revealed to be Algernon's older brother, and his real name is in fact Ernest","He is revealed to be Lady Bracknell's son","He is revealed to be a fraud with no family at all"], ans:1, expl:"In the play's farcical resolution, Jack discovers he was named 'Ernest' after his father — making his invented identity accidentally true." },
    { q:"Who is Lady Bracknell in The Importance of Being Earnest?", opts:["A kind, generous aunt who supports young love","Algernon's formidable aunt and Gwendolen's mother, who embodies rigid Victorian social snobbery","Jack's housekeeper","A rival suitor for Gwendolen"], ans:1, expl:"Lady Bracknell's interrogation of Jack's suitability (including the famous 'handbag' scene) satirises the obsession with social status and respectability in Victorian marriage." },
    { q:"What is Gwendolen Fairfax's stated reason for wanting to marry a man named 'Ernest'?", opts:["She has known an Ernest since childhood","She finds the name itself inspires absolute confidence, regardless of the man's actual character — satirising superficial Victorian values","Her father insists on it","It is a family tradition"], ans:1, expl:"Gwendolen's declaration that she could never love a man not named Ernest satirises how superficial qualities were valued over genuine character in courtship." },
    { q:"What is the role of Miss Prism and Dr Chasuble in The Importance of Being Earnest?", opts:["They are the play's villains","They provide a comic subplot of late-life romance and represent figures of supposed moral and intellectual authority undercut by farce","They are Jack's biological parents","They are foreign diplomats"], ans:1, expl:"Miss Prism (a governess with a scandalous past — losing a baby in a handbag) and Dr Chasuble (a clergyman) add comic romance while satirising figures of supposed respectability." },
    { q:"How does the discovery of the handbag resolve the plot of The Importance of Being Earnest?", opts:["It reveals hidden treasure","It reveals that Jack was the baby Miss Prism mistakenly left in a handbag at a train station, confirming his true identity and family connections","It contains a will that changes everyone's fortunes","It is never found"], ans:1, expl:"Miss Prism's confession about the handbag resolves the mystery of Jack's parentage in classic farcical fashion, allowing the play's marriages to proceed." },
    { q:"What does 'The Ballad of Reading Gaol' (1898) describe?", opts:["A romantic adventure","Wilde's experience of prison life and his reflection on the execution of a fellow prisoner, written after his release","A satire of London high society","A fairy tale for children"], ans:1, expl:"Written after Wilde's release from Reading Gaol, the poem reflects on suffering, guilt and the execution of a soldier-prisoner — far removed from his earlier comic works." },
    { q:"What is the significance of the line 'Each man kills the thing he loves' from The Ballad of Reading Gaol?", opts:["It refers literally only to the executed prisoner","It serves as the poem's central refrain, reflecting on universal guilt, destructive love and human cruelty — possibly with personal resonance for Wilde","It is a quote from Shakespeare embedded in the poem","It has no thematic significance"], ans:1, expl:"This refrain universalises the poem's meditation on guilt and destruction, moving beyond the specific prisoner's story to a broader statement on human nature." },
    { q:"What were the 'Wilde trials' of 1895?", opts:["Civil trials over a business dispute","A series of criminal trials in which Wilde was prosecuted for 'gross indecency' due to his relationships with men, ultimately resulting in his imprisonment","Trials over copyright infringement of his plays","Trials that exonerated Wilde completely"], ans:1, expl:"After Wilde sued the Marquess of Queensberry for libel and lost, he was himself prosecuted and convicted under laws criminalising homosexuality." },
    { q:"Who was the Marquess of Queensberry in relation to Wilde?", opts:["Wilde's publisher","The father of Lord Alfred Douglas (Wilde's lover), whose accusations triggered the chain of events leading to Wilde's trials","Wilde's editor","A fellow playwright and rival"], ans:1, expl:"Queensberry's note accusing Wilde of being a 'posing somdomite' [sic] led Wilde to sue for libel — a disastrous decision that exposed him to prosecution." },
    { q:"What happened to Wilde after his release from prison in 1897?", opts:["He returned triumphantly to London society","He lived in exile in France under the name 'Sebastian Melmoth', in poverty and declining health until his death in 1900","He became a successful politician","He stopped writing entirely but lived comfortably"], ans:1, expl:"Wilde spent his final years in exile, largely estranged from former friends and in financial difficulty, dying in Paris in 1900." },
    { q:"What is the central paradox explored in many of Wilde's epigrams?", opts:["Wilde's epigrams contain no paradoxes","Wilde frequently inverts conventional wisdom (e.g. 'I can resist everything except temptation') to expose hypocrisy and challenge accepted moral assumptions","Wilde's epigrams are always literally true","Wilde avoided humour in his writing"], ans:1, expl:"Wilde's paradoxical wit destabilises conventional Victorian moral certainties, often revealing uncomfortable truths beneath comic surfaces." },
    { q:"What does the character of Dorian Gray ultimately come to represent by the end of the novel?", opts:["The triumph of beauty over morality with no consequences","The destructive consequences of a life devoted entirely to pleasure, vanity and the avoidance of consequence — his external youth masking total moral corruption","A model of successful self-improvement","A martyr for artistic freedom"], ans:1, expl:"Dorian's spiritual corruption, hidden behind unchanging beauty, ultimately destroys him — his stabbing of the portrait reunites his appearance with his true, withered soul." },
    { q:"How does Wilde's Irish background relate to his role as a social critic of English society?", opts:["It made him entirely uninterested in English society","As an outsider to the English establishment (despite his success within it), Wilde was positioned to observe and satirise its hypocrisies with particular sharpness","It prevented him from being accepted in London at all","He never engaged with English social themes"], ans:1, expl:"Wilde's position as a brilliant Irish outsider in English society gave him both access to and critical distance from the customs he satirised." },
    { q:"What is 'Vivian' and 'Cyril' debating in Wilde's essay 'The Decay of Lying'?", opts:["Politics and economics","The relationship between art and truth, with Vivian arguing that art should not imitate nature but create beautiful, imaginative falsehoods","Religious doctrine","Sporting events"], ans:1, expl:"In this dialogue-essay, Wilde (through Vivian) argues that good art should be imaginative and 'lie' beautifully, rather than merely copy reality — a key statement of his aesthetic theory." },
    { q:"What does Wilde mean by 'Life imitates Art far more than Art imitates Life'?", opts:["Art has no influence on real life","Wilde argues that people often shape their behaviour, perceptions, and even appearance based on artistic representations, reversing the usual assumption that art simply reflects life","This statement does not appear in Wilde's work","It refers only to theatrical performances"], ans:1, expl:"This famous paradox, from 'The Decay of Lying', exemplifies Wilde's challenge to realist assumptions about the relationship between art and reality." },
    { q:"What is the significance of the title 'The Importance of Being Earnest' as a pun?", opts:["It has no double meaning","It plays on the word 'earnest' (sincere, serious) versus the name 'Ernest', highlighting the gap between appearing sincere and actually being so","It refers to a real historical figure named Ernest","It is simply a literal title with no wordplay"], ans:1, expl:"The pun encapsulates the play's central irony: characters who claim to value 'earnestness' (sincerity) build their lives on elaborate deceptions." },
    { q:"How is marriage satirised in The Importance of Being Earnest?", opts:["Marriage is presented as purely romantic and sincere","Marriage is treated as a social and financial transaction, with characters more concerned with names, status and convenience than genuine love","The play contains no marriages or engagements","Marriage is shown as entirely impossible for the characters"], ans:1, expl:"Lady Bracknell's interrogation of Jack and Gwendolen's fixation on the name 'Ernest' both reduce marriage to superficial concerns, satirising Victorian attitudes." },
    { q:"What is the function of food and eating (e.g. cucumber sandwiches, muffins) in The Importance of Being Earnest?", opts:["Food has no significance in the play","Comic scenes involving food (such as Algernon eating all the cucumber sandwiches) provide farcical humour and reveal characters' self-indulgence amid supposedly serious conversations","Food is used only to show poverty","All characters refuse to eat throughout the play"], ans:1, expl:"The absurd seriousness with which characters discuss trivial matters like sandwiches, while ignoring weightier issues, exemplifies the play's satirical inversion of priorities." },
    { q:"What does Algernon's invented friend 'Bunbury' allow him to do?", opts:["Travel abroad freely with no excuses needed","Escape unwanted social obligations (like dinners with Aunt Augusta) under the pretext of visiting his sick friend","Avoid marriage altogether permanently","Gain a large inheritance"], ans:1, expl:"'Bunburying' becomes a running joke and metaphor for the convenient double lives maintained by both Algernon and Jack." },
    { q:"How does the structure of The Importance of Being Earnest reflect the conventions of farce?", opts:["It avoids all farcical elements, being purely realistic","It uses mistaken identities, elaborate coincidences, rapid-fire dialogue and a neatly contrived resolution typical of farce","It has a tragic ending typical of classical tragedy","It follows no recognisable theatrical conventions"], ans:1, expl:"The play's reliance on disguise, coincidence (the handbag) and a perfectly timed resolution are hallmarks of the farce genre, which Wilde elevates with his wit." },
    { q:"What is the relationship between aestheticism and decadence in late Victorian culture?", opts:["They are unrelated movements","Decadence is often seen as an intensification of aestheticism, emphasising artificiality, excess, and the cultivation of refined (sometimes perverse) sensations over conventional morality","Decadence predates aestheticism by centuries","Aestheticism rejected all forms of beauty"], ans:1, expl:"While aestheticism emphasised 'art for art's sake', decadence pushed further into themes of excess, artificiality and moral transgression — both influenced Wilde's work." },
    { q:"What is the significance of Dorian Gray's interest in 'collecting' (jewels, perfumes, music, tapestries)?", opts:["It shows Dorian's frugality","His obsessive collecting of beautiful objects reflects his pursuit of ever more refined sensations as a substitute for moral or emotional depth — a hallmark of decadent aestheticism","It shows Dorian is preparing to sell his possessions","It has no connection to his character development"], ans:1, expl:"Dorian's elaborate cataloguing of sensory pleasures (echoing À Rebours) illustrates the emptiness beneath his cultivated, aestheticised existence." },
    { q:"How does Basil Hallward's view of art differ from Lord Henry's?", opts:["They hold identical views","Basil believes art should be a sincere expression of the artist's feeling and is troubled by putting 'too much of himself' into the portrait, while Lord Henry views art and life as material for amoral aesthetic experimentation","Basil has no interest in art at all","Lord Henry believes art must always have a moral message"], ans:1, expl:"Basil's anxiety about revealing too much of his own soul in the portrait of Dorian contrasts with Lord Henry's detached, experimental approach to both art and people." },
    { q:"What does the phrase 'the love that dare not speak its name' (from a poem by Lord Alfred Douglas, referenced in Wilde's trial) refer to?", opts:["Romantic love between a man and woman that is socially acceptable","A euphemistic reference to homosexual love, which was criminalised and socially taboo in Victorian England","Religious devotion","Love of art"], ans:1, expl:"This phrase, from Douglas's poem, became famously associated with Wilde's trial when he was asked to explain it — his response was a notable defence of love between men." },
    { q:"What is Wilde's view on the relationship between beauty and morality, as dramatised through Dorian Gray's fate?", opts:["Wilde argues beauty guarantees moral goodness","While Wilde's aestheticism separated art from morality, the novel's plot (Dorian's downfall) can be read as showing that a life devoted purely to beauty and pleasure, without moral consideration, leads to self-destruction","Wilde argues morality is irrelevant to all aspects of life","The novel shows beauty and morality are unrelated with no consequences either way"], ans:1, expl:"Critics debate whether Dorian Gray's tragic ending undercuts or reinforces Wilde's aestheticism — some read it as a moral fable despite Wilde's claims in the preface." },
    { q:"What is the significance of Dorian's interest in the occult and exotic religions in the novel?", opts:["It shows Dorian becomes devoutly religious","Dorian's dabbling in various exotic philosophies and rituals reflects his restless search for new sensations to fill an inner emptiness, without any genuine spiritual commitment","It leads to his redemption","It is the cause of his initial corruption"], ans:1, expl:"Dorian's superficial flirtations with various religions and philosophies exemplify the decadent pursuit of novel sensations rather than genuine meaning." },
    { q:"How does the novel depict the world of London's criminal underclass (opium dens, etc.) that Dorian visits?", opts:["As an idealised escape from society","As squalid, dangerous spaces that reveal the depths to which Dorian's pursuit of sensation has led him, beneath his respectable public facade","As entirely fictional locations with no realism","As spaces of genuine spiritual enlightenment"], ans:1, expl:"Dorian's secret visits to opium dens expose the gulf between his glittering public reputation and the degraded reality of his private life." },
    { q:"What role does James Vane, Sybil's brother, play in the novel?", opts:["He is Dorian's close friend","He vows revenge against Dorian for his sister's death and is accidentally killed during a hunting party years later, having mistaken Dorian for someone else initially","He becomes a famous actor like his sister","He marries Lord Henry's daughter"], ans:1, expl:"James Vane's pursuit of Dorian for revenge, and his eventual accidental death, haunts Dorian with the fear of consequences finally catching up with him." },
    { q:"What does Dorian's reaction to James Vane's death reveal about his character at that point in the novel?", opts:["Dorian feels deep remorse and reforms immediately","Dorian feels only relief and a brief, superficial unease, quickly suppressed — showing how thoroughly his conscience has been deadened","Dorian turns himself in to the police","Dorian had no knowledge of James Vane's existence"], ans:1, expl:"Dorian's ability to dismiss the death of a man who sought to kill him, with barely a thought, demonstrates the depth of his moral corruption by this point." },
    { q:"How does Wilde use the setting of fashionable London society in Dorian Gray?", opts:["London society is portrayed as entirely virtuous","Fashionable society is shown as superficial, gossip-driven and willing to overlook Dorian's reputed sins as long as he remains charming, beautiful and wealthy — a critique of social hypocrisy","The novel is set entirely outside London","Society immediately ostracises Dorian for any wrongdoing"], ans:1, expl:"Despite whispered rumours about Dorian's corrupting influence on others, society continues to welcome him — exposing its superficial values and willingness to overlook vice in the beautiful and powerful." },
    { q:"What is the effect of Wilde's frequent use of epigrams and aphorisms throughout his plays and novel?", opts:["They slow down the plot with irrelevant detail","They create a distinctive comic and intellectual style, often using paradox to challenge conventional thinking while entertaining the audience","They are used only in serious, tragic moments","They are absent from his plays"], ans:1, expl:"Wilde's epigrammatic wit ('I can resist everything except temptation') is central to his comic style and serves as a vehicle for social critique." },
    { q:"What is the significance of the setting of the portrait's final transformation at the novel's climax?", opts:["The portrait is destroyed in a fire","Dorian stabs the portrait in the locked attic room, and the knife instead kills Dorian himself — his body becomes withered and ugly while the portrait is restored to its original beauty","The portrait simply disappears","Dorian gives the portrait to a museum"], ans:1, expl:"The final reversal — Dorian's body bears the portrait's corruption while the portrait returns to its pristine state — completes the novel's central supernatural conceit." },
    { q:"How is the theme of vanity explored through Dorian Gray's character?", opts:["Dorian shows no vanity throughout the novel","Dorian's initial wish to remain eternally young, and his subsequent obsession with preserving his appearance at any cost, exemplifies the destructive potential of vanity taken to a supernatural extreme","Vanity is portrayed as a harmless and positive trait","Dorian's vanity is cured early in the novel"], ans:1, expl:"Dorian's casual wish — that the portrait could age instead of him — sets the entire tragedy in motion, making vanity the root of his downfall." },
    { q:"What is notable about the critical reception of The Picture of Dorian Gray upon its 1890 publication?", opts:["It was universally praised as wholesome family literature","It was widely condemned by critics as immoral and decadent, which led Wilde to revise and expand it for the 1891 book edition, adding the preface defending art for art's sake","It was banned and never published","It received no critical attention at all"], ans:1, expl:"The novel's scandalous reception prompted Wilde to add chapters and the now-famous preface, explicitly defending the autonomy of art from moral judgement." },
    { q:"How does Wilde present the contrast between youth and age in Dorian Gray?", opts:["Age is presented as more desirable than youth throughout","Youth and beauty are initially presented (especially by Lord Henry) as supremely valuable, almost the only things worth having — a view the novel ultimately complicates through Dorian's fate","Youth and age are treated as equally unimportant","The novel does not address this theme"], ans:1, expl:"Lord Henry's worship of youth as fleeting and precious sets up Dorian's tragic wish, while the novel's outcome questions whether youth without wisdom or conscience is truly desirable." },
    { q:"What is the function of Lady Bracknell's interrogation scene in The Importance of Being Earnest in terms of social satire?", opts:["It satirises the legal system","It satirises the way the upper classes evaluated potential marriage partners based on wealth, property and social connections rather than character", "It satirises religious institutions","It satirises the education system only"], ans:1, expl:"Lady Bracknell's checklist-like questioning of Jack (income, property, parentage) exposes the transactional nature of upper-class Victorian marriage." },
    { q:"How does Wilde's own life (his trials and imprisonment) affect modern readings of his earlier comic works?", opts:["It has no effect — the works are read in isolation","Modern readers often find darker undertones (about hidden identities, double lives, and societal hypocrisy regarding sexuality) in plays like Earnest, given knowledge of Wilde's later persecution","It makes the comic works seem entirely unrelated to his life","His later life makes his earlier works seem less significant"], ans:1, expl:"The theme of secret 'double lives' (Bunburying, Jack/Ernest) takes on additional resonance when read alongside Wilde's own concealment of his sexuality in a hostile society." },
    { q:"What is Wilde's general stance on Victorian moral hypocrisy as expressed across his work?", opts:["He fully endorses Victorian moral codes","Wilde repeatedly exposes the gap between the rigid public morality professed by Victorian society and the private behaviour of its members, often with comic or tragic effect","He never addresses morality in his work","He argues Victorian society had no moral codes at all"], ans:1, expl:"From Dorian Gray's secret corruption to the double lives in Earnest, Wilde consistently highlights the disconnect between public respectability and private reality." },
    { q:"What does the title 'A Woman of No Importance' suggest about Wilde's treatment of gender and social status?", opts:["It celebrates women's full equality in society","The ironic title points to how society dismisses women (particularly those with a 'past' or lower status) as unimportant, while the play explores the consequences of this dismissal","It refers to a minor character with no role in the plot","It has no connection to gender themes"], ans:1, expl:"Like much of Wilde's work, the title's irony critiques how Victorian society judged and dismissed women based on social respectability and reputation." },
    { q:"How does Wilde use the figure of the 'New Woman' or independent female characters in his plays?", opts:["Wilde never includes independent female characters","Some of Wilde's female characters display wit, intelligence and independence that subtly challenge — even as the plays' plots often resolve within conventional marriage structures — traditional gender expectations","All of Wilde's female characters are entirely passive","Wilde's plays exclude women from speaking roles"], ans:1, expl:"Characters like Gwendolen and Cecily display sharp wit and assertiveness, even as the plays' farcical resolutions ultimately channel them toward marriage." },
    { q:"What is the broader cultural legacy of Oscar Wilde's wit and persona?", opts:["He is remembered only for his trials, with no literary legacy","Wilde remains one of the most quoted writers in English, celebrated for his epigrams, plays and novel, while also being recognised as an important figure in LGBTQ+ history due to his persecution","His work has been entirely forgotten","His legacy is purely as a fashion icon with no literary importance"], ans:1, expl:"Wilde's enduring quotability and the continued performance of his plays, alongside his historical significance as a victim of anti-homosexuality laws, secure his lasting cultural importance." },
    { q:"What is the significance of Dorian Gray giving Sybil Vane the nickname 'Sibyl'/referring to her by her stage roles (e.g. as Juliet)?", opts:["Dorian falls in love with Sybil as a real, complex individual","Dorian initially loves Sybil only as an idealised artistic performer (e.g. as Shakespeare's Juliet), not as a real person — once she abandons acting for real love, he loses interest, revealing his shallow aestheticism","Dorian and Sybil never discuss her acting career","Sybil rejects Dorian before he can reject her"], ans:1, expl:"Dorian's love for Sybil is revealed to be love for art/illusion rather than for a real person — when she acts badly because she has fallen in love for real, he cruelly abandons her." },
    { q:"What does the conclusion of The Importance of Being Earnest, with its multiple marriages, suggest about Wilde's attitude toward conventional comic resolutions?", opts:["Wilde rejects marriage as a comic resolution entirely","While the play ends with the traditional comic resolution of marriages, the absurdity of how these resolutions are achieved (via the handbag, the name Ernest) satirises the artificiality of such 'happy endings'","The play ends with no resolution at all","All characters remain single at the end"], ans:1, expl:"By making the resolution depend on such contrived coincidences, Wilde simultaneously delivers and gently mocks the conventions of comic drama." },
    { q:"How does Wilde's use of foreign settings or references (e.g. Algeria, the East) function in his work?", opts:["Foreign settings are entirely absent from Wilde's work","Exotic references often serve as symbols of forbidden pleasure, escape from English convention, or sources of decadent sensation for characters like Dorian Gray","Foreign settings are always portrayed negatively as dangerous","Wilde's work is set entirely in foreign countries"], ans:1, expl:"References to exotic locations and objects in Dorian Gray contribute to the novel's atmosphere of decadent escapism and the pursuit of novel sensations." },
    { q:"What is the role of secrecy and concealment as a recurring motif across Wilde's major works?", opts:["Secrecy appears in none of Wilde's works","From the locked portrait in Dorian Gray to the invented identities in Earnest, concealment of one's true self or past is a recurring structural and thematic device","All of Wilde's characters are entirely transparent about themselves","Secrecy is used only for minor comic effect with no thematic weight"], ans:1, expl:"The motif of hidden truths — a portrait, a double identity, a hidden past — runs throughout Wilde's work and arguably reflects the pressures of concealment in his own life." },
    { q:"How does the ending of The Picture of Dorian Gray align with or subvert the conventions of the Gothic genre?", opts:["It has no Gothic elements at all","It employs Gothic conventions (a supernatural object, a hidden secret, a violent climax, moral retribution) while updating them to a contemporary aesthetic/decadent setting","It is set in a medieval castle typical of pure Gothic fiction","The ending is entirely comic, undermining any Gothic tone"], ans:1, expl:"The supernatural portrait, hidden room, and Dorian's violent death are all Gothic devices, transplanted into the world of fashionable 1890s London society." },
    { q:"What is the significance of the novel's final image — servants finding 'a withered, wrinkled, loathsome' corpse that they can only identify by Dorian's rings?", opts:["It shows Dorian's body is unrecognisable, completing the reversal between Dorian and the portrait, and stripping away the beauty that had concealed his corruption for so long","It shows the portrait was destroyed instead","It shows Dorian escaped and faked his death","It has no symbolic significance"], ans:0, expl:"The final grotesque image confirms that all the corruption hidden in the portrait has now transferred to Dorian's body — the truth is finally made visible." },
    { q:"What is the role of Lady Bracknell's catchphrase-like dismissals (e.g. 'A handbag?!') in The Importance of Being Earnest?", opts:["They show her warmth and approachability","Her exaggerated, theatrical reactions to trivial matters epitomise the play's comic style, where social trivialities are treated with mock-seriousness","They are meant to be taken as genuine outrage with real consequences","They reveal her hidden affection for Jack"], ans:1, expl:"Lady Bracknell's disproportionate reactions to minor social details (like being raised in a handbag) are central to the play's comic inversion of serious and trivial matters." },
    { q:"How does Wilde characterise the difference between town and country life in The Importance of Being Earnest?", opts:["Country life is shown as dull and town life as exciting, with no irony","Both settings are satirised as equally artificial, with characters maintaining elaborate pretences and double identities in both locations","The play is set entirely in the countryside","Town and country are never contrasted in the play"], ans:1, expl:"Jack's 'Earnest' persona in town and Algernon's 'Bunbury' excuse for visiting the country both show that pretence and double lives pervade every setting in the play." },
    { q:"What does Cecily Cardew's diary represent in The Importance of Being Earnest?", opts:["A factual record of events as they happened","Cecily's romantic fantasies, including her invented engagement to 'Ernest' (Algernon posing as Jack's brother) before they had even met — blurring fiction and reality","A historical document used as legal evidence","A list of household chores"], ans:1, expl:"Cecily's diary, in which she has already 'recorded' a romance with the fictional Ernest before meeting Algernon, humorously mirrors the novel's blurring of invented and real identities." },
    { q:"How does Wilde's combination of comedy and social critique in Earnest differ from straightforward moral satire?", opts:["Wilde delivers his social critique through direct moral lectures by characters","Wilde embeds his critique within a frothy, seemingly inconsequential comic plot, allowing audiences to laugh while absorbing pointed observations about class and hypocrisy","The play contains no social critique, being pure entertainment","The play abandons comedy entirely in its final act"], ans:1, expl:"Wilde's genius lies in disguising sharp social commentary within seemingly trivial farce — the comedy is the vehicle for the critique, not separate from it." },
    { q:"What is the significance of Dorian Gray reading the 'yellow book' repeatedly over many years?", opts:["He reads it once and never again","Dorian becomes obsessed with the book, seeing his own life mirrored in its decadent protagonist — it becomes a kind of corrupting guide to his existence","He uses it as a cookbook","He gives it away immediately after reading it"], ans:1, expl:"The yellow book's poisonous influence on Dorian, which he returns to repeatedly, exemplifies Wilde's exploration of how art can shape — and corrupt — a life." },
    { q:"What is the effect of Wilde setting Dorian Gray in contemporary (late Victorian) London rather than a historical or foreign setting?", opts:["It makes the novel's themes feel distant and irrelevant to readers","Setting the supernatural story among recognisable London society and locations heightens the unsettling effect — corruption lurks beneath a familiar, respectable surface","The contemporary setting removes all Gothic elements","It was a requirement of the publisher"], ans:1, expl:"By placing Gothic horror within fashionable contemporary London, Wilde suggests that moral corruption can exist beneath the most polished, modern surfaces." },
    { q:"How does Lord Henry's marriage (and his wife's eventual departure) function in the novel?", opts:["It shows Lord Henry as a devoted family man","Lord Henry's failed marriage exemplifies his own theories about the incompatibility of his hedonistic philosophy with conventional domestic life — though he remains untouched by real consequence, unlike Dorian","It is the central plot of the novel","Lord Henry has no wife in the novel"], ans:1, expl:"Lord Henry's wife eventually leaves him, but he remains socially and emotionally unaffected — a minor illustration of how his theories play out without the catastrophic consequences Dorian suffers." },
    { q:"What does the phrase 'the only difference between a saint and a sinner is that every saint has a past, and every sinner has a future' (Wilde) suggest about his view of moral categories?", opts:["Wilde firmly believed in fixed, permanent moral categories","Wilde's paradoxes often suggest that moral identities are fluid and that redemption or fall is always possible — destabilising rigid Victorian moral binaries","This quote argues sinners can never change","The quote is unrelated to morality"], ans:1, expl:"Typical of Wilde's epigrammatic style, this paradox challenges the fixed moral categories of saint and sinner, suggesting moral identity is always in flux." },
    { q:"What is the significance of Basil Hallward's reluctance to exhibit the portrait of Dorian Gray publicly at the start of the novel?", opts:["He believes the portrait is poorly painted","He fears the portrait reveals too much of his own feelings for Dorian, putting 'too much of himself' into the work — establishing the theme of art revealing hidden truths about its creator","He has already sold the portrait","He is legally forbidden from exhibiting it"], ans:1, expl:"Basil's anxiety about the portrait exposing his own soul foreshadows how the portrait will later expose Dorian's soul instead." },
    { q:"How does Wilde use the motif of mirrors and reflection beyond the portrait itself in Dorian Gray?", opts:["Mirrors never appear in the novel besides the portrait","Dorian's growing aversion to ordinary mirrors, and his eventual reliance on the portrait as the only 'true' reflection of himself, reinforces the theme of the gap between appearance and reality","Dorian collects mirrors as part of his hobby with no symbolic meaning","Mirrors are used only in the final scene"], ans:1, expl:"The contrast between Dorian's unchanging mirror image and the portrait's decay reinforces the central conceit of hidden versus visible truth." },
    { q:"What broader argument about censorship and art does the controversy over The Picture of Dorian Gray illustrate?", opts:["Victorian critics universally supported artistic freedom","The hostile reception illustrates Victorian anxieties about literature's potential moral influence, and Wilde's responses (the preface, revisions) became a defence of artistic freedom from moral policing","The novel was never controversial in any way","Censorship had no impact on Wilde's work"], ans:1, expl:"The controversy over Dorian Gray's perceived immorality fed into broader late-Victorian debates about the limits of artistic freedom versus social/moral responsibility — debates that also shaped the climate of Wilde's later trials." },
    { q:"What does Lord Henry mean when he says 'There is only one thing worse than being talked about, and that is not being talked about'?", opts:["He believes privacy is the highest virtue","He expresses a cynical, celebrity-driven view that any attention — even scandal — is preferable to obscurity, reflecting the values of the decadent society depicted","He is warning Dorian against seeking fame","The quote refers only to political figures"], ans:1, expl:"This epigram captures Lord Henry's (and the novel's broader) satirical take on a society obsessed with reputation and notoriety over substance." },
    { q:"What is the significance of Wilde describing himself in De Profundis as embodying the art and culture of his age?", opts:["Wilde modestly downplayed his cultural importance","Wilde saw his rise and fall as symbolic of broader tensions between aestheticism and Victorian respectability","This statement refers only to his finances","Wilde rejected any connection between his life and his art"], ans:1, expl:"In De Profundis, Wilde reflects on his own life as emblematic of the artistic and moral conflicts of his time." },
    { q:"How does the character of Mrs Erlynne in Lady Windermere's Fan challenge Victorian notions of the 'fallen woman'?", opts:["She is punished severely and dies at the end","She is portrayed sympathetically and ultimately acts selflessly to protect her daughter's reputation, complicating simplistic moral judgements about women with a 'past'","She has no role in the play's resolution","She is revealed to be entirely virtuous from the start with no scandal"], ans:1, expl:"Mrs Erlynne's self-sacrifice for Lady Windermere subverts the stock 'fallen woman' figure, who in conventional Victorian drama would typically be condemned." },
    { q:"What is the function of the fan in Lady Windermere's Fan?", opts:["It is a purely decorative prop with no plot significance","It is a symbolic object whose presence at a compromising moment threatens to expose secrets and drive the play's central misunderstanding","It is used as a weapon in a duel","It represents the title character's wealth only"], ans:1, expl:"The fan, left behind at Lord Darlington's rooms, becomes the object around which the play's crisis of reputation and misunderstanding revolves." },
    { q:"What does Wilde's play An Ideal Husband examine?", opts:["A perfect marriage with no secrets","A politician's past indiscretion threatens his public reputation, exploring themes of public versus private morality and forgiveness","A husband searching for a new wife","A comedy about cooking"], ans:1, expl:"An Ideal Husband examines whether a person can be forgiven for a past moral lapse and still be considered 'ideal', satirising the gap between public image and private history." },
    { q:"How does Wilde use the salon/drawing-room setting common to his plays?", opts:["These settings are used for action scenes like duels","The drawing-room setting confines the action to fashionable society spaces, emphasising performance, gossip, and the policing of reputation within elite social circles","The plays are set in rural farms","The setting changes to a different country in each act"], ans:1, expl:"The drawing-room comedy format Wilde employed situates his social satire within the very spaces where Victorian high society performed its rituals of respectability." },
    { q:"What is the typical structure of a Wildean 'problem play' (e.g. Lady Windermere's Fan, An Ideal Husband)?", opts:["A pure comedy with no serious themes","A blend of witty comic dialogue with a serious moral dilemma involving secrets, reputation, and social scandal, often resolved through forgiveness or concealment","A tragedy ending in multiple deaths","A play with no plot, only dialogue"], ans:1, expl:"Wilde's 'society' or 'problem' plays combine epigrammatic wit with melodramatic plots about hidden pasts and the threat of social ruin." },
    { q:"What does the recurring theme of blackmail in Wilde's plays (e.g. An Ideal Husband) reveal about Victorian society?", opts:["Blackmail was not a concern in Victorian drama","It reveals the immense power of reputation and secrecy in a society where a single revealed indiscretion could destroy a person's social and political standing","Blackmail is portrayed as a harmless joke","It shows Victorian society had no interest in scandal"], ans:1, expl:"The high stakes of blackmail plots in Wilde's plays reflect a society obsessed with maintaining a spotless public reputation at any cost." },
    { q:"How does Wilde's combination of French farce techniques with English social satire characterise his comic plays?", opts:["He rejected French theatrical influence entirely","Wilde adapted French farce's rapid pacing, mistaken identities and tight plotting to skewer specifically English social manners and class distinctions","His plays follow no theatrical tradition","French farce techniques are absent from Earnest"], ans:1, expl:"Wilde blended the structural techniques of French farce with sharply English subject matter — class, marriage, and respectability — to create his distinctive comic style." },
    { q:"What is the significance of Wilde's epigram 'Work is the curse of the drinking classes' (an inversion of a common saying)?", opts:["It is a straightforward statement Wilde genuinely believed about labour","It exemplifies Wilde's technique of inverting common proverbs to create comic, paradoxical effects that also subtly mock class assumptions","It refers literally to factory workers","It has no relation to Wilde's style"], ans:1, expl:"By inverting the cliché 'drink is the curse of the working classes', Wilde both amuses and subtly inverts assumptions about class and morality." },
    { q:"How did Wilde's time at Oxford University influence his later persona and work?", opts:["Oxford had no influence on Wilde","At Oxford, Wilde was influenced by aesthetic and classical ideas (including from Walter Pater and John Ruskin) that shaped his later devotion to beauty, individualism and unconventional self-presentation","Wilde dropped out of Oxford after one term","Wilde studied only mathematics at Oxford"], ans:1, expl:"Wilde's exposure to aestheticism and classical scholarship at Oxford laid the intellectual foundation for his later artistic philosophy and flamboyant public persona." },
    { q:"What is the significance of Wilde's American lecture tour (1882) on the topic of aestheticism?", opts:["It was a financial and critical disaster with no cultural impact","It helped popularise (and often satirise, via caricatures) the aesthetic movement in America, cementing Wilde's reputation as its most flamboyant spokesperson","Wilde refused to discuss aesthetics during the tour","The tour took place after Wilde's death"], ans:1, expl:"Wilde's American tour, complete with his distinctive dress and manner, brought aestheticism — and Wilde himself — significant public attention (and parody) on both sides of the Atlantic." },
    { q:"How does the concept of the 'mask' relate to Wilde's characters and his own public persona?", opts:["Wilde's characters are always completely sincere and transparent","Many of Wilde's characters adopt social 'masks' — performed identities that conceal their true selves — paralleling Wilde's own carefully cultivated public wit and persona as a kind of performance","Masks appear only in his poetry, never his plays or novel","The concept of a 'mask' is irrelevant to Wilde's work"], ans:1, expl:"The gap between the social self (mask) and the private self is a recurring concern in Wilde's work, resonant with his own management of a public image versus private life." },
    { q:"What does the phrase 'nothing to declare except my genius', reportedly said by Wilde to customs officials, illustrate about his public image?", opts:["Wilde was modest about his abilities","Wilde cultivated a persona of supreme self-confidence and wit, turning even mundane encounters into opportunities for memorable, quotable performance","The quote shows Wilde disliked attention","Wilde was being literal about his luggage"], ans:1, expl:"Whether apocryphal or not, this remark exemplifies the carefully performed wit that made Wilde as famous for his persona as for his writing." },
    { q:"How does Wilde's fairy tale 'The Happy Prince' differ in tone from his society comedies?", opts:["It is equally comic and satirical with no emotional depth","It is a poignant, often melancholic tale about selflessness and social injustice, told in a simpler, more sentimental register aimed partly at children but carrying serious moral weight","It is identical in style to The Importance of Being Earnest","It has no moral content at all"], ans:1, expl:"'The Happy Prince' shows Wilde's range beyond witty social satire — using the fairy tale form to address poverty, sacrifice and compassion with genuine pathos." },
    { q:"What does the statue's sacrifice of its jewels and gold leaf in 'The Happy Prince' symbolise?", opts:["Greed and selfishness as positive values","Selfless generosity and compassion for the suffering of the poor, even at the cost of the statue's own beauty — contrasting outer beauty with inner goodness","The statue's vanity","A critique of religious institutions only"], ans:1, expl:"The Happy Prince statue gradually gives away all its beauty to help the poor of the city, illustrating that true value lies in compassion rather than appearance — a theme that complicates simple readings of Wilde as purely an aesthete indifferent to morality." }
  );

  /* ══ VIRGINIA WOOLF (+86) ══ */
  window.QUIZ_DATA.woolf.push(
    { q:"What is the significance of the title 'Mrs Dalloway' rather than 'Clarissa'?", opts:["It emphasises Clarissa's social identity as defined by her marriage and role as hostess, rather than her individual selfhood","It refers to a different character entirely","It was the publisher's choice with no thematic meaning","It indicates the novel is about Mr Dalloway"], ans:0, expl:"The title 'Mrs Dalloway' foregrounds the social, married identity that Clarissa inhabits publicly, while the novel's interior exploration reveals the complex self beneath that label." },
    { q:"What is Clarissa Dalloway's reaction to news of Septimus's suicide at her party?", opts:["She is indifferent and continues the party as planned","She feels a profound, almost mystical connection to his act, recognising in his death an assertion of freedom she herself has never taken","She faints and the party is cancelled","She blames herself directly for his death"], ans:1, expl:"Clarissa's complex reaction — feeling that Septimus's suicide was somehow 'right', an act of defiance — connects her life-affirming party to his death in an unexpected way." },
    { q:"What is the role of Peter Walsh in Mrs Dalloway?", opts:["Clarissa's husband","Clarissa's former suitor who returns to London and reflects on what their relationship might have been","Septimus's doctor","Clarissa's brother"], ans:1, expl:"Peter Walsh, who Clarissa rejected years earlier in favour of Richard Dalloway, returns and prompts reflections on choice, regret and the paths not taken." },
    { q:"How does Woolf depict Dr Bradshaw and Dr Holmes in relation to Septimus?", opts:["As compassionate, effective healers who cure Septimus","As representatives of a rigid medical establishment that fails to understand or properly treat Septimus's trauma, contributing to his despair","As Septimus's close friends","As minor characters with no significance"], ans:1, expl:"The doctors' insistence on 'proportion' and conventional treatment, with no real engagement with Septimus's inner suffering, is part of Woolf's critique of how society handles mental illness." },
    { q:"What does Big Ben's chiming throughout Mrs Dalloway represent?", opts:["A purely decorative sound effect","The relentless, external passage of clock time against which the characters' subjective, fluid experiences of time are contrasted","A warning of war","A symbol of Clarissa's youth"], ans:1, expl:"The repeated striking of Big Ben punctuates the novel, providing a structural counterpoint to the characters' wandering, non-linear inner thoughts." },
    { q:"What is the significance of flowers in Mrs Dalloway (e.g. Clarissa buying flowers for her party)?", opts:["Flowers have no symbolic role","Flowers represent beauty, life, and Clarissa's attempt to create meaning and connection through small, sensory pleasures amid the larger uncertainties of existence","Flowers symbolise death exclusively","Flowers represent Clarissa's wealth only"], ans:1, expl:"The opening image of Clarissa buying flowers establishes her appreciation for beauty and ordinary pleasures as a way of affirming life." },
    { q:"How does To the Lighthouse structure its three sections ('The Window', 'Time Passes', 'The Lighthouse')?", opts:["All three sections cover the same single day","'The Window' covers a day before WWI, 'Time Passes' compresses ten years (including WWI and deaths) into a brief interlude, and 'The Lighthouse' returns to the family ten years later","The novel has only one section","Each section is set in a different country"], ans:1, expl:"The dramatic shift in pacing — a single day stretched over hundreds of pages, then a decade compressed into a short section — exemplifies Woolf's experimental treatment of time." },
    { q:"What happens to Mrs Ramsay in To the Lighthouse?", opts:["She dies suddenly during the 'Time Passes' section, reported in brackets amid descriptions of the empty house","She leads the family to the lighthouse herself","She becomes estranged from her family","She is the novel's narrator throughout"], ans:0, expl:"Mrs Ramsay's death is conveyed almost parenthetically — a stark, understated narrative choice that emphasises how individual lives are absorbed into time's larger flow." },
    { q:"What does the lighthouse trip, finally completed in the third section, represent for Mr Ramsay and his children?", opts:["A simple holiday activity with no deeper meaning","A long-deferred goal that, once achieved, carries the weight of loss, memory, and reconciliation with the past, particularly the absence of Mrs Ramsay","A scientific expedition","An escape from a storm"], ans:1, expl:"The journey to the lighthouse, postponed since the novel's opening, becomes loaded with emotional significance once finally undertaken after Mrs Ramsay's death." },
    { q:"How does Lily Briscoe's painting relate to Mrs Ramsay's character?", opts:["Lily's painting has nothing to do with Mrs Ramsay","Lily's struggle to capture the relationship between Mrs Ramsay and her son James in her painting reflects the broader artistic challenge of representing fleeting human connection and meaning","Lily paints only landscapes with no human figures","Mrs Ramsay refuses to be painted"], ans:1, expl:"Lily's eventual completion of her painting, achieving a kind of 'vision', parallels the novel's own attempt to capture and preserve the essence of Mrs Ramsay and a moment in time." },
    { q:"What is the significance of the recurring image of the sea in To the Lighthouse?", opts:["The sea represents only danger and is avoided by all characters","The sea's constant presence and rhythm reflect the passage of time, the unconscious, and forces larger than individual human lives", "The sea appears only in the final chapter","The sea is purely a backdrop with no thematic resonance"], ans:1, expl:"The sound and sight of the sea recur throughout the novel, often linked to characters' innermost thoughts and the vast impersonal forces of time and nature." },
    { q:"What is Woolf's 'A Room of One's Own' based on?", opts:["A series of lectures Woolf delivered to women's colleges at Cambridge","A personal diary entry","A government report on education","A novel about Cambridge University"], ans:0, expl:"The essay developed from two lectures Woolf gave at Newnham and Girton Colleges, Cambridge, on the topic of 'Women and Fiction'." },
    { q:"What historical example does Woolf use in 'A Room of One's Own' to illustrate women's exclusion from literary tradition?", opts:["The fictional 'Shakespeare's sister', whose talents would have been crushed by the social constraints placed on women","Jane Austen's wealthy background","The career of Charles Dickens","The success of male poets only"], ans:0, expl:"Woolf's famous thought experiment imagines a sister of Shakespeare with equal genius, whose story illustrates how social conditions, not lack of talent, prevented women from creating great literature." },
    { q:"What is Woolf's view of 'androgyny' in the writer's mind, as discussed in 'A Room of One's Own'?", opts:["Writers should write only from a strictly male or strictly female perspective","The greatest writing comes from a mind that transcends rigid gender categories, drawing on both 'masculine' and 'feminine' qualities","Androgyny is irrelevant to literary creation","Woolf rejects the concept entirely"], ans:1, expl:"Woolf suggests that the most creative minds are 'androgynous' — not dominated by an awareness of their own sex — citing Shakespeare as an example of this balance." },
    { q:"What is the 'Time Passes' section of To the Lighthouse notable for stylistically?", opts:["It is the longest section of the novel with detailed dialogue","It uses an unusual, almost impersonal narrative voice and compresses years into a short space, marked by parenthetical statements about deaths and the passage of time","It is written entirely in verse","It focuses entirely on a single character's perspective"], ans:1, expl:"The 'Time Passes' section radically shifts perspective, depicting the empty house and the passage of WWI years through an impersonal, almost cosmic narrative voice." },
    { q:"How does Woolf's depiction of WWI differ between Mrs Dalloway and To the Lighthouse?", opts:["WWI is absent from both novels","In Mrs Dalloway, the war's aftermath is explored through Septimus's trauma; in To the Lighthouse, the war occurs 'offstage' during the 'Time Passes' section, marked by loss and the passage of time","Both novels depict the war through direct battle scenes","WWII is the war depicted in both novels"], ans:1, expl:"Woolf consistently avoids direct depiction of battle, instead exploring war's psychological and temporal aftermath on those who remain." },
    { q:"What is the significance of Clarissa Dalloway's memory of kissing Sally Seton in her youth?", opts:["It is a minor, forgotten detail with no significance","It represents a moment of intense passion and freedom in Clarissa's past, contrasting with the more conventional, restrained life she has chosen as Mrs Dalloway","It represents Clarissa's first meeting with her husband","It is presented as a negative, regretted memory"], ans:1, expl:"The memory of Sally Seton represents an alternative, more passionate possibility in Clarissa's life — one she ultimately did not pursue, adding to the novel's exploration of choices and their consequences." },
    { q:"What does the character Doris Kilman represent in Mrs Dalloway?", opts:["A close friend of Clarissa's who shares her values","A religious, resentful woman who has an intense (and somewhat possessive) relationship with Clarissa's daughter Elizabeth, representing a contrasting worldview to Clarissa's","Clarissa's sister","A doctor treating Septimus"], ans:1, expl:"Miss Kilman's religious fervour and bitterness toward Clarissa's class and lifestyle provide a contrasting perspective, while her relationship with Elizabeth raises questions about influence and possessiveness." },
    { q:"What is the effect of Woolf's use of free indirect discourse in her novels?", opts:["It creates clear separation between narrator and character thoughts","It blends the narrator's voice with characters' inner thoughts so seamlessly that the boundary between external narration and internal consciousness becomes fluid","It is used only for dialogue","It eliminates all narrative voice entirely"], ans:1, expl:"Free indirect discourse allows Woolf to move fluidly between characters' minds and an narratorial perspective without clear demarcation, creating the immersive stream-of-consciousness effect." },
    { q:"How does Woolf's essay 'Professions for Women' extend the arguments of 'A Room of One's Own'?", opts:["It focuses on a completely unrelated topic","It discusses the psychological obstacles (like the internalised 'Angel in the House') that women writers must overcome, beyond just material/economic barriers","It argues women should not pursue professional careers","It was written before 'A Room of One's Own'"], ans:1, expl:"'Professions for Women' addresses internal, psychological barriers — particularly the self-censoring 'Angel in the House' — that complement the material barriers discussed in A Room of One's Own." },
    { q:"What does Woolf mean by the 'Angel in the House' in her essay 'Professions for Women'?", opts:["A literal ghost that haunts Woolf's house","An internalised ideal of selfless, accommodating femininity that women writers must 'kill' in order to express their own honest thoughts","A character in one of her novels","A positive role model Woolf encourages women to emulate"], ans:1, expl:"The 'Angel in the House' represents the internalised social expectation that women should be sympathetic, charming, and self-sacrificing — Woolf argues this figure must be confronted and overcome for honest writing." },
    { q:"What is the significance of the party as a recurring structural device in Mrs Dalloway?", opts:["The party is mentioned only briefly at the end with no structural role","Clarissa's party serves as the novel's central organising event, toward which all the day's events build, and at which various character threads converge","The party takes place at the very beginning of the novel","There is no party in the novel"], ans:1, expl:"The preparation for and execution of Clarissa's party structures the single-day narrative, providing a focal point that draws together the novel's various characters and themes." },
    { q:"How does Woolf use the device of strangers' lives intersecting briefly in Mrs Dalloway (e.g. the car, the skywriting aeroplane)?", opts:["These devices have no narrative function","Brief shared moments (like a car's passage or a skywriting plane observed by many characters) link the otherwise separate inner lives of strangers across London, creating a sense of interconnected human experience","These devices are used only once, with no thematic repetition","They serve only to advance the plot mechanically"], ans:1, expl:"These moments of shared observation across the city create a web of connection between characters who never meet, reflecting Woolf's interest in the interconnectedness of urban life." },
    { q:"What does Septimus Warren Smith's profession before the war (a clerk who aspired to be a poet) signify?", opts:["It shows he had no ambitions before the war","It establishes him as a sensitive, aspirational figure whose potential was destroyed by the war's trauma — a loss the novel mourns alongside his death","It shows he was wealthy before the war","It is unrelated to the novel's themes"], ans:1, expl:"Septimus's pre-war aspirations toward poetry and culture make his post-war breakdown and the medical establishment's failure to help him especially poignant." },
    { q:"How does Woolf depict Rezia, Septimus's wife, in Mrs Dalloway?", opts:["As indifferent to Septimus's suffering","As a loving but increasingly isolated and desperate figure, struggling to care for a husband whose inner world she cannot access or the doctors adequately address","As the cause of Septimus's mental illness","As a minor character who never appears"], ans:1, expl:"Rezia's loneliness and helplessness as Septimus's caretaker — far from her native Italy, unsupported by the medical establishment — adds to the novel's critique of how society handles trauma." },
    { q:"What does the recurring phrase 'Fear no more the heat o' the sun' (from Shakespeare's Cymbeline) signify in Mrs Dalloway?", opts:["It is an unrelated quotation with no thematic significance","It is a recurring motif associated with death and acceptance, appearing in the thoughts of both Clarissa and Septimus, linking their otherwise separate stories","It refers to a literal heatwave in the novel","It is sung at Clarissa's party"], ans:1, expl:"This Shakespearean line about death's release from suffering recurs in both Clarissa's and Septimus's thoughts, subtly connecting their parallel meditations on mortality." },
    { q:"How does Woolf's novel Orlando play with the conventions of biography?", opts:["It follows strict factual biographical conventions","It presents itself as a biography while including fantastical elements (a 400-year lifespan, a sex change), satirising the genre's claims to objective truth and stable identity","It rejects the biography form entirely, using only poetry","It is a biography of Woolf herself"], ans:1, expl:"By framing a fantastical story as a 'biography', Woolf playfully exposes the constructed, often gendered, nature of biographical and historical narrative." },
    { q:"What is the significance of Orlando's transformation from male to female partway through the novel?", opts:["It has no effect on the character or narrative","It allows Woolf to explore how gender shapes social experience, expectations and opportunities across different historical periods, while the character's essential self remains continuous","Orlando reverts to male immediately","The novel ends at this point"], ans:1, expl:"Orlando's seamless transition, met with little narrative fuss, allows Woolf to highlight the arbitrary and constructed nature of gender roles across the centuries Orlando lives through." },
    { q:"How long does Orlando live, and what does this lifespan allow Woolf to explore?", opts:["A normal human lifespan, set in a single historical period","Several centuries, from the Elizabethan era to the 1920s, allowing Woolf to explore changing literary, social and gender norms across English history","Only a single day, like Mrs Dalloway","Orlando is immortal and never ages at all"], ans:1, expl:"Orlando's extraordinarily long life serves as a vehicle for Woolf to satirically survey changing English literary and social history from the late 16th century to her own time." },
    { q:"What is the dedication of Orlando, and what does it suggest about the novel's inspiration?", opts:["It has no dedication","It is dedicated to Vita Sackville-West, Woolf's close friend and lover, whose family history and androgynous persona partly inspired the character of Orlando","It is dedicated to Woolf's husband Leonard","It is dedicated to Lytton Strachey"], ans:1, expl:"Orlando is often described as 'the longest and most charming love letter in literature', inspired by and dedicated to Vita Sackville-West." },
    { q:"What is Woolf's critique of traditional realist fiction in her essay 'Modern Fiction'?", opts:["She argues realist fiction perfectly captures human experience","She argues that materialist, plot-driven realist novels (citing writers like Arnold Bennett) fail to capture the true, fragmented and fluid nature of consciousness and experience","She argues fiction should focus only on external events","She has no critique of realism"], ans:1, expl:"Woolf's 'Modern Fiction' criticises 'materialist' novelists for focusing on external detail at the expense of representing the inner life — a critique that underpins her own stream-of-consciousness technique." },
    { q:"How does Woolf's depiction of social class function in Mrs Dalloway?", opts:["The novel ignores class distinctions entirely","Class differences are subtly woven throughout — from Clarissa's privileged social world to Miss Kilman's resentment and Septimus's lower-middle-class background — shaping characters' experiences and relationships","All characters belong to the same social class","Class is the novel's sole focus, overshadowing all other themes"], ans:1, expl:"Woolf subtly maps social class onto her characters' inner lives and interactions, contributing to the novel's broader social portrait of post-WWI England." },
    { q:"What does the character of Mr Ramsay represent in To the Lighthouse?", opts:["An entirely sympathetic, nurturing father figure","A rigid, intellectually demanding figure whose need for sympathy and validation contrasts with Mrs Ramsay's more intuitive, relational way of engaging with others","A minor character with little development","Mrs Ramsay's brother"], ans:1, expl:"Mr Ramsay's philosophical rigidity and emotional neediness are often read as representing a 'masculine' mode of thought, contrasted with Mrs Ramsay's intuitive 'feminine' mode — though Woolf complicates this binary." },
    { q:"How does Woolf's own mental health history relate to her depiction of Septimus Warren Smith?", opts:["Woolf had no personal experience of mental illness","Woolf herself suffered from severe mental illness throughout her life, and her depiction of Septimus's experience — including his treatment by doctors — is informed by this personal experience","Septimus is based entirely on a historical political figure unrelated to Woolf","Woolf wrote Septimus's character before she ever experienced mental illness herself"], ans:1, expl:"Woolf's own struggles with what would now likely be diagnosed as bipolar disorder, and her experiences with the medical establishment, inform the harrowing realism of Septimus's sections." },
    { q:"What does the essay 'A Room of One's Own' suggest is necessary, beyond money and space, for women to write fiction?", opts:["Nothing else is necessary beyond money and space","Freedom from interruption, social expectation, and the psychological burden of conforming to others' (particularly men's) expectations of how women should think and write","A formal university education is the only other requirement","Marriage to a supportive husband"], ans:1, expl:"While Woolf emphasises material conditions (£500 a year and a room with a lock), she also discusses the psychological freedom needed to write 'the truth about my own experiences as a body'." },
    { q:"How does Woolf use punctuation and sentence structure to convey stream of consciousness?", opts:["She uses only short, simple sentences throughout","She often uses long, flowing sentences with semicolons, dashes, and shifting clauses to mimic the continuous, associative movement of thought","She avoids all punctuation entirely","She uses standard, conventional punctuation with no experimentation"], ans:1, expl:"Woolf's syntax — long sentences that loop through associations, interruptions and shifts in focus — formally enacts the experience of consciousness she seeks to represent." },
    { q:"What is the significance of the Ramsay children's various ambitions and personalities in To the Lighthouse?", opts:["The children are undifferentiated and interchangeable","Each child (e.g. James's resentment of his father, Cam's conflicted loyalty) represents different responses to their parents and to the passage of time, especially evident in the final section's boat journey","The children do not appear in the novel","All the children die during the novel"], ans:1, expl:"The surviving children's complex feelings toward their parents, especially as adults in the final section, reflect the lasting impact of family dynamics and loss." },
    { q:"What does the recurring motif of windows in To the Lighthouse (beginning with the title of the first section) suggest?", opts:["Windows have no thematic significance","Windows function as thresholds between inner and outer worlds, between the domestic space and the wider world (including the lighthouse), and between different characters' perspectives","Windows represent only physical barriers to be avoided","The novel contains no references to windows beyond the section title"], ans:1, expl:"The window, through which Mrs Ramsay and James gaze out at the lighthouse in the opening section, becomes a recurring symbol of perspective, separation and connection." },
    { q:"How does Woolf's background as part of the Bloomsbury Group shape the themes of her work?", opts:["The Bloomsbury Group had no influence on her writing","The group's progressive views on art, sexuality, and rejection of Victorian conventions are reflected in Woolf's experimental forms and her exploration of inner life, gender and relationships","Woolf was opposed to all the Bloomsbury Group's ideas","The Bloomsbury Group focused only on economics, which is unrelated to Woolf's fiction"], ans:1, expl:"The Bloomsbury Group's anti-Victorian, intellectually open ethos — including frank discussion of sexuality and rejection of conventional moral and aesthetic codes — deeply informed Woolf's worldview and writing." },
    { q:"What is the importance of memory and the past in Mrs Dalloway?", opts:["The novel takes place entirely in the present with no reference to the past","Characters' inner lives are constantly shaped by memories of the past (Clarissa's youth, Peter's old feelings, Septimus's pre-war self), which intermingle with the present 'now' of the single day","Memory is mentioned only once, briefly","All characters have lost their memories"], ans:1, expl:"The novel's stream-of-consciousness technique allows past and present to coexist in characters' minds, showing how memory continuously shapes present experience." },
    { q:"How does the ending of To the Lighthouse resolve (or not resolve) the novel's central tensions?", opts:["All tensions are neatly and completely resolved with a happy ending","The lighthouse trip is finally completed and Lily finishes her painting, achieving a sense of completion and 'vision', but this comes after profound loss (Mrs Ramsay's death) and cannot undo what has passed","The novel ends with the family's complete destruction","The ending reveals the entire novel was a dream"], ans:1, expl:"The achievement of long-deferred goals (the lighthouse trip, Lily's painting) provides a sense of resolution, but it is bittersweet, arriving only after irrevocable loss." },
    { q:"What does Woolf's phrase 'the cotton wool of daily life' refer to?", opts:["A literal description of clothing","The dull, unremarkable texture of ordinary, unreflective existence, against which 'moments of being' stand out as sudden illuminations","A description of London's weather","A metaphor for old age"], ans:1, expl:"Woolf used this phrase (in her memoir 'A Sketch of the Past') to describe the numbing ordinariness of much of life, contrasted with rare 'moments of being' that pierce through it." },
    { q:"How does the structure of Mrs Dalloway (a single day) compare to that of James Joyce's Ulysses?", opts:["The two novels share no structural similarities","Both novels are famously structured around a single day in a city, using stream-of-consciousness to explore the inner lives of multiple characters — Woolf was aware of and responded to Joyce's experimental techniques","Ulysses takes place over several years, unlike Mrs Dalloway","Mrs Dalloway was written long before Ulysses and could not have been influenced by it"], ans:1, expl:"Both Mrs Dalloway (1925) and Ulysses (1922) compress a vast inner world into a single day, reflecting a shared Modernist interest in the relationship between everyday time and consciousness — though Woolf had mixed views on Joyce's novel." },
    { q:"What is the function of the character Sir William Bradshaw's emphasis on 'proportion' in Mrs Dalloway?", opts:["'Proportion' is presented as a genuinely helpful medical philosophy","Bradshaw's worship of 'proportion' represents a complacent, conformist social and medical establishment that pathologises difference and fails to engage with genuine suffering","Proportion refers to mathematical concepts unrelated to medicine","Bradshaw is the novel's most sympathetic character"], ans:1, expl:"Woolf satirises Bradshaw's 'goddess of Proportion' as emblematic of an establishment more interested in enforcing social conformity than understanding individual suffering." },
    { q:"How does Woolf use the motif of the 'crack in the wall' or similar images of fracture in her work?", opts:["Such images never appear in her work","Images of cracks, gaps and fractures often symbolise moments where ordinary reality breaks down, revealing deeper truths, instability, or the fragility of the self","These images always represent literal building damage with no symbolism","They represent only physical danger to characters"], ans:1, expl:"Woolf frequently uses imagery of breaks or fissures in surfaces to suggest moments where the ordinary world gives way to deeper psychological or existential realities." },
    { q:"What does the final line of To the Lighthouse, 'I have had my vision', spoken by Lily Briscoe, signify?", opts:["Lily has given up on her painting entirely","Lily achieves a moment of artistic and personal completion, having finally captured something true about Mrs Ramsay, the family, and the passage of time in her painting","Lily has had a religious revelation unrelated to her art","The line refers to Mr Ramsay's vision, not Lily's"], ans:1, expl:"Lily's completion of her painting at the novel's end represents a culmination of the novel's exploration of art, memory, and the attempt to give permanent form to fleeting experience." },
    { q:"How does Woolf depict the experience of ageing across her novels (e.g. Clarissa Dalloway, Mrs Ramsay)?", opts:["Ageing is never addressed in her work","Woolf's characters often reflect on the passage of time, lost youth, and the gap between their inner sense of self and their outward appearance or social role as they age","All her major characters are children","Ageing is depicted as entirely negative with no complexity"], ans:1, expl:"Characters like Clarissa Dalloway reflect on time's passage and the persistence of a youthful inner self beneath an aging exterior, a recurring concern in Woolf's exploration of identity." },
    { q:"What is the significance of Woolf's own suicide note(s) in relation to the themes of her fiction?", opts:["Her suicide has no connection to her fiction's themes","Woolf's own death by suicide adds a tragic real-life dimension to her fiction's recurring exploration of mental illness, despair, and the search for relief from suffering (as seen in Septimus's story)","Woolf's suicide note expressed only anger at her critics","There is no documented connection between her life and her work's themes"], ans:1, expl:"While critics caution against reducing Woolf's work to autobiography, the parallels between her own struggles and characters like Septimus are widely discussed in understanding her fiction's emotional depth." },
    { q:"How does Woolf challenge conventional narrative chronology in her fiction?", opts:["She always follows strict chronological order","She frequently disrupts linear time through flashbacks, compressed time periods, and the fluid movement between past and present within characters' consciousness","Chronology is irrelevant because her novels have no time setting","Her novels are told entirely in reverse order"], ans:1, expl:"From the single-day structure of Mrs Dalloway to the decade-spanning compression of 'Time Passes', Woolf consistently experiments with how time is represented in fiction." },
    { q:"What broader feminist argument does 'A Room of One's Own' make about literary canon formation?", opts:["The literary canon has always fairly represented women's contributions","The canon has been shaped by historical conditions that systematically excluded women from the resources (education, money, privacy) needed to produce recognised literature, not by any lack of female talent","Woolf argues women should not aspire to enter the canon","The essay does not discuss the literary canon"], ans:1, expl:"Woolf's central argument is structural: the apparent absence of great women writers in history reflects material and social barriers, not an absence of female genius." },
    { q:"How does Woolf's narrative technique in To the Lighthouse shift between characters' perspectives?", opts:["The novel is told from a single character's perspective throughout","The narrative moves fluidly between the perspectives of multiple characters, sometimes within a single paragraph, without explicit signposting — a technique sometimes called 'multiple consciousness'","The novel uses only third-person omniscient narration with no access to individual minds","Each chapter is narrated by a different character in clearly marked first person"], ans:1, expl:"Woolf's fluid shifts between characters' inner perspectives, often without clear transition, immerses readers in a collective, shifting consciousness rather than a single fixed viewpoint." },
    { q:"What publishing venture did Virginia Woolf and her husband Leonard found?", opts:["The Times Literary Supplement","The Hogarth Press, which published Woolf's own works as well as those of other Modernist writers","Penguin Books","Faber and Faber"], ans:1, expl:"The Hogarth Press, founded in 1917, gave Woolf creative control over the publication of her experimental works, free from commercial publishers' pressures." },
    { q:"What is the significance of Woolf publishing her own novels through the Hogarth Press?", opts:["It had no effect on her writing","It gave her complete artistic freedom to experiment with form and content without needing to satisfy commercial publishers, enabling her radical narrative techniques","It meant her novels were never properly distributed","It was purely a financial necessity with no creative benefit"], ans:1, expl:"Editorial independence from mainstream publishing allowed Woolf to pursue increasingly experimental techniques across her novels." },
    { q:"What is the title of Woolf's first novel, published in 1915?", opts:["Mrs Dalloway","The Voyage Out","Jacob's Room","Night and Day"], ans:1, expl:"The Voyage Out (1915) is Woolf's first novel, more conventional in form than her later experimental works but already exploring themes of female experience and self-discovery." },
    { q:"What is Jacob's Room (1922) notable for?", opts:["It is a straightforward biography of a real person","It portrays its central character, Jacob, almost entirely through the impressions and perspectives of others, leaving his inner life largely absent — reflecting his eventual death in WWI","It is Woolf's only comic novel","It was written after Woolf's death"], ans:1, expl:"Jacob's Room's indirect, fragmented portrayal of its protagonist — who is killed in WWI — embodies the sense of absence and loss the war left behind." },
    { q:"What does Woolf's novel The Waves (1931) experiment with?", opts:["A conventional plot with a clear beginning, middle and end","Six characters' interior monologues interspersed with poetic interludes describing the sea and the passage of a day, pushing stream of consciousness to its most abstract extreme","A detective story format","A historical account of WWI battles"], ans:1, expl:"The Waves abandons conventional plot almost entirely, presenting the lives of six friends through their interior soliloquies, framed by lyrical descriptions of the natural world." },
    { q:"What is the significance of the recurring figure of Percival in The Waves?", opts:["Percival is the novel's narrator","Percival, who dies partway through the novel, is a unifying figure for the six central characters, and his death prompts reflection on loss, friendship and mortality","Percival never appears or is mentioned in the novel","Percival represents the novel's villain"], ans:1, expl:"Though he never speaks himself, Percival's presence (and later his death) binds together the perspectives of the other six characters, who each respond to him and his loss differently." },
    { q:"What is Between the Acts (1941), Woolf's final novel, primarily concerned with?", opts:["A war fought entirely overseas with no connection to England","A village pageant performed on the eve of WWII, used to reflect on English history, community, and the looming threat of war","A courtroom drama","A romance set in Italy"], ans:1, expl:"Published posthumously, Between the Acts uses an amateur historical pageant to meditate on English identity, continuity and rupture as Europe stood on the brink of WWII." },
    { q:"When and how did Virginia Woolf die, and how does Between the Acts relate to this?", opts:["She died of old age decades after writing it; the novel has no connection","She completed Between the Acts shortly before taking her own life in 1941, giving the novel's themes of impending crisis and uncertainty an added poignancy","She died while writing the novel, which was left unfinished and later completed by another author","The novel was written fifty years before her death"], ans:1, expl:"Woolf drowned herself in the River Ouse in 1941, shortly after completing Between the Acts, and her wartime anxieties are reflected in the novel's atmosphere of foreboding." },
    { q:"What does Woolf's diary reveal about her writing process for Mrs Dalloway?", opts:["She wrote the novel in a single sitting with no revision","Her diaries show she experimented considerably with structure and originally conceived a different ending, reflecting her ongoing struggle to find the right form for representing consciousness","She wrote the novel reluctantly at her publisher's insistence with no personal investment","Her diaries contain no references to her own writing"], ans:1, expl:"Woolf's diaries are a valuable record of her creative struggles, including her evolving plans for Mrs Dalloway (originally to be called 'The Hours') and her search for an appropriate form." },
    { q:"What was the working title of Mrs Dalloway during its composition?", opts:["The Lighthouse","The Hours","The Waves","Orlando"], ans:1, expl:"Woolf initially called the novel 'The Hours', a title that emphasises the structuring presence of clock time against which the characters' inner lives unfold." },
    { q:"How does Woolf depict London as a city in Mrs Dalloway?", opts:["London is depicted as a dull, lifeless backdrop","London is depicted vividly and almost as a character itself — its streets, parks, shops and sounds woven into the characters' perceptions and memories","The novel is set entirely in the countryside","London appears only in a single short scene"], ans:1, expl:"The city's sensory richness — traffic, shop windows, parks — becomes integral to the novel's exploration of consciousness, as characters' thoughts are continually triggered by their urban surroundings." },
    { q:"What is the significance of Septimus's hallucinations involving his dead friend Evans?", opts:["Evans is a living character who visits Septimus","Septimus's hallucinatory visions of his dead comrade Evans reflect his unresolved trauma from the war and his inability to grieve normally","Evans represents a doctor treating Septimus","Evans is revealed to be Septimus's brother"], ans:1, expl:"Septimus's visions of Evans, killed in the war, illustrate the lingering psychological wounds of combat — what would now be recognised as PTSD." },
    { q:"What does Richard Dalloway's character represent in contrast to Peter Walsh?", opts:["Richard represents passionate, romantic intensity","Richard represents a stable, conventional, if somewhat emotionally undemonstrative, choice — the life Clarissa chose over the more turbulent possibilities Peter represented","Richard and Peter are the same character under different names","Richard is portrayed as cruel and abusive"], ans:1, expl:"Clarissa's marriage to the reliable but reserved Richard, rather than the passionate but difficult Peter, represents one of the novel's central explorations of choice and its lasting emotional consequences." },
    { q:"How does Woolf use the technique of 'tunnelling' (her own term) in her fiction?", opts:["It refers to a physical setting in her novels","Woolf described 'tunnelling' as her process of digging into characters' pasts and psychology to reveal them gradually through layers of memory and association, rather than direct exposition","It refers to a type of punctuation she invented","It describes her method of editing manuscripts"], ans:1, expl:"Woolf's own description of 'tunnelling' captures her technique of revealing character through accumulated layers of memory, sensation and association rather than straightforward narrative exposition." },
    { q:"What is the relationship between Virginia Woolf and Vita Sackville-West, and how did it influence her work?", opts:["They were professional rivals with no personal relationship","They had a close romantic and intellectual relationship, which directly inspired Orlando and influenced Woolf's exploration of gender and identity","They never met in person","Vita Sackville-West was Woolf's editor only"], ans:1, expl:"Woolf's relationship with Vita Sackville-West, a writer and aristocrat, was a major influence on Orlando and on Woolf's thinking about gender, sexuality and social convention." },
    { q:"What does the essay 'Three Guineas' (1938) address?", opts:["A purely personal financial matter unrelated to broader themes","The connections between patriarchy, fascism and war, arguing that women's exclusion from power and education is linked to the broader societal structures that enable violence and tyranny","A guide to writing fiction","A history of the Bloomsbury Group"], ans:1, expl:"'Three Guineas' extends Woolf's feminist analysis to argue that the patriarchal structures within domestic and professional life are connected to the militarism and authoritarianism threatening Europe in the 1930s." },
    { q:"How does Woolf characterise the relationship between sanity and 'madness' through Septimus's character?", opts:["Septimus's experiences are presented as simply incorrect perceptions to be corrected","Woolf presents Septimus's visions and perceptions with a kind of poetic validity, suggesting that what society labels 'madness' may contain its own form of insight, even as it causes him to suffer","Septimus is depicted as entirely rational and the doctors as irrational with no nuance","Madness is treated purely as comic material"], ans:1, expl:"Woolf's sympathetic, often lyrical rendering of Septimus's inner experience complicates a simple division between sanity and madness, even as it depicts the real suffering his condition causes." },
    { q:"What is the significance of the recurring motif of the 'leaden circles' of Big Ben's chimes 'dissolving in the air'?", opts:["It describes a literal weather phenomenon","It captures the way clock time, though rigid and structured, ultimately dissolves into the more fluid, subjective experience of consciousness depicted in the novel","It refers to smoke from factories","It has no connection to the novel's treatment of time"], ans:1, expl:"This recurring image — the sound of Big Ben spreading and fading — beautifully captures the tension and ultimate intermingling of objective clock time and subjective psychological time central to the novel." },
    { q:"How does Woolf's depiction of marriage in Mrs Dalloway compare across different couples (the Dalloways, the Smiths)?", opts:["All marriages in the novel are depicted identically as happy","The novel presents a range of marital relationships — from the Dalloways' companionable but emotionally distant marriage to the Smiths' marriage strained by Septimus's trauma — exploring different forms of intimacy, distance and care","Marriage is not depicted at all in the novel","Only one marriage appears in the entire novel"], ans:1, expl:"By presenting multiple marriages with varying degrees of intimacy, understanding and strain, Woolf builds a nuanced picture of relationships across class and circumstance." },
    { q:"What is the role of Clarissa's daughter Elizabeth in Mrs Dalloway?", opts:["Elizabeth represents the older generation's values","Elizabeth represents a younger generation with different opportunities and outlooks than her mother, caught between her mother's social world and Miss Kilman's influence","Elizabeth dies during the novel","Elizabeth is the novel's narrator"], ans:1, expl:"Elizabeth's relationships with both her mother and Miss Kilman, and her own emerging sense of independence, hint at a generational shift in women's possibilities." },
    { q:"What does the structure of To the Lighthouse, with its emphasis on a single object (the lighthouse) as a goal, suggest about human desire and aspiration?", opts:["The lighthouse is reached easily early in the novel with no significance","The long-deferred journey to the lighthouse symbolises how human desires and goals are often delayed, transformed by time and loss, and ultimately bittersweet when finally achieved","The lighthouse is never mentioned again after the title","The lighthouse represents only a navigational aid with no symbolic weight"], ans:1, expl:"The deferred lighthouse trip becomes a powerful symbol for how time, loss and changed circumstances alter the meaning of long-held goals by the time they are finally realised." },
    { q:"How does Woolf's treatment of class differ between her portrayal of the Ramsays (To the Lighthouse) and the working-class characters who appear briefly in her novels?", opts:["Working-class characters are given equal narrative depth and interiority as upper-middle-class characters throughout her work","Woolf has been critiqued for primarily focusing on the interior lives of upper-middle-class, intellectual characters, with working-class figures often appearing only briefly or from an external perspective","Woolf wrote exclusively about working-class characters","Class is entirely absent from all her novels"], ans:1, expl:"Critics have noted that while Woolf's fiction explores consciousness with great depth, this depth is generally reserved for educated, upper-middle-class characters, reflecting both her own background and the limits of her social world." },
    { q:"What is the significance of the recurring image of waves in The Waves beyond its title?", opts:["Waves appear only in the title with no further significance","The interludes describing waves and the changing light of day over the sea provide a recurring rhythm and structure, paralleling the rise and fall of the characters' lives from childhood to old age","The waves represent a literal shipwreck central to the plot","The waves symbolise only danger and destruction"], ans:1, expl:"The poetic interludes depicting the sea's waves across a single day mirror the broader arc of the six characters' lives, suggesting cyclical, natural patterns underlying individual human experience." },
    { q:"How does Woolf use interior monologue differently for male and female characters in her fiction?", opts:["She gives interior monologue only to male characters","Woolf gives rich interior lives to characters of all genders, often using the technique to challenge assumptions about which perspectives (traditionally male, 'important' figures) deserve narrative attention","She gives interior monologue only to female characters","There is no difference in her treatment of male and female characters' inner lives"], ans:1, expl:"By granting deep interiority to female characters like Clarissa and Mrs Ramsay — traditionally seen as 'domestic' and therefore narratively unimportant — Woolf challenges literary conventions about whose consciousness merits exploration." },
    { q:"What is the significance of Woolf's frequent depiction of characters' awareness of mortality within ordinary moments?", opts:["Mortality is never mentioned in her work","Woolf often shows characters suddenly confronting thoughts of death amid everyday activities (shopping, parties, painting), reflecting her belief that profound experience coexists with the mundane","Mortality is addressed only in her non-fiction essays","Her characters are never aware of their own mortality"], ans:1, expl:"The juxtaposition of ordinary activity with sudden awareness of mortality — as when Clarissa reflects on death while buying flowers — is a hallmark of Woolf's exploration of 'moments of being'." },
    { q:"How does the ending of Mrs Dalloway leave Clarissa's story?", opts:["Clarissa dies at the end of the novel","The novel ends with Clarissa returning to her party, having processed Septimus's death in her own way, suggesting life continues with its mixture of beauty, loss and ongoing uncertainty","Clarissa leaves her husband at the end","The novel ends with a flashback to Clarissa's childhood"], ans:1, expl:"The novel's ending — Clarissa's return to her party after her private reflection on Septimus's death — exemplifies Woolf's preference for ambiguous, open-ended resolutions over neat conclusions." },
    { q:"What does the phrase 'she felt very young; at the same time unspeakably aged' (referring to Clarissa) capture about Woolf's treatment of identity and time?", opts:["It is a contradiction that Woolf resolves clearly","It captures Woolf's interest in the coexistence of multiple, even contradictory, senses of self across time within a single individual — identity as layered rather than singular","It refers only to Clarissa's physical appearance","It indicates Clarissa has amnesia"], ans:1, expl:"This kind of paradoxical self-perception — feeling simultaneously young and old — exemplifies Woolf's interest in how the past remains alive within the present self." },
    { q:"How did contemporary critics initially respond to Woolf's experimental techniques?", opts:["Her techniques were immediately and universally celebrated with no controversy","Responses were mixed — while some recognised her innovations as significant contributions to Modernism, others found her work difficult, plotless, or overly focused on trivial details of consciousness","Her work was completely ignored during her lifetime","All critics agreed her techniques were a failure"], ans:1, expl:"Woolf's departure from conventional plot and character development drew both admiration from fellow Modernists and criticism from those who found her work inaccessible or lacking in 'substance'." },
    { q:"What is the significance of Woolf's portrayal of objects (e.g. a shawl, a brooch, flowers) carrying emotional weight in her novels?", opts:["Objects are never significant in her work","Ordinary objects often become charged with memory and emotion for Woolf's characters, serving as triggers for reflection and connecting present moments to the past","Objects are described only for realistic detail with no emotional resonance","Her novels avoid describing physical objects entirely"], ans:1, expl:"Small objects frequently serve as catalysts for the associative movement of memory and emotion that characterises Woolf's stream-of-consciousness technique." },
    { q:"How does Woolf's work reflect anxieties about the British Empire and its decline?", opts:["Her work shows no interest in empire or its decline","Through characters and settings touched by empire (such as Peter Walsh's time in India, or Septimus's experience of war partly fought to defend imperial interests), Woolf's fiction reflects the broader unease of a society whose imperial confidence was shaken by WWI","Her work celebrates the British Empire without any critique","Empire is the central, explicit subject of all her novels"], ans:1, expl:"References to colonial settings and experiences appear throughout Woolf's work as part of the broader social fabric whose certainties were being questioned in the post-WWI period." },
    { q:"What is the significance of the contrast between Mrs Ramsay's intuitive social skills and Mr Ramsay's philosophical work in To the Lighthouse?", opts:["The novel presents Mr Ramsay's work as clearly more valuable than Mrs Ramsay's social skills","The novel gives serious narrative weight to Mrs Ramsay's relational, intuitive 'work' of creating harmony and connection, implicitly questioning hierarchies that value abstract intellectual achievement over relational and emotional labour","Mrs Ramsay has no skills or role in the novel","Mr Ramsay's philosophical work is portrayed as entirely successful and fulfilling"], ans:1, expl:"By devoting careful attention to Mrs Ramsay's social and emotional labour — often dismissed as 'merely' domestic — Woolf elevates forms of work traditionally undervalued in a male-dominated intellectual culture." },
    { q:"How does Woolf's fiction engage with the idea of a 'unified self' versus a fragmented or multiple self?", opts:["Woolf consistently presents characters as having a single, unchanging, unified identity","Woolf's characters often experience themselves as composed of many different selves across time and context, challenging the idea of a single, stable, unified identity","The concept of self is entirely absent from her fiction","Woolf argues that only fictional characters, not real people, have multiple selves"], ans:1, expl:"Characters like Clarissa and Orlando experience their identities as layered, shifting and context-dependent, reflecting Modernist questioning of a stable, unified selfhood." },
    { q:"What does the phrase 'moments of being' contrast with in Woolf's autobiographical writing?", opts:["It contrasts with moments of sleep only","It contrasts with the 'non-being' of ordinary, unreflective daily routine — 'moments of being' are rare instances of heightened awareness and significance that punctuate the 'cotton wool' of everyday life","It contrasts with moments of writing","It contrasts with moments spent with family"], ans:1, expl:"Woolf's concept distinguishes between the largely unremembered, unreflective texture of daily life ('non-being') and the comparatively rare moments of vivid, meaningful experience ('being')." }
  );
})();
